insert into aura_exercise_catalog (id, payload, updated_at) values
  ('7E382CCC-FC42-52FE-8D6A-6C07F958F332'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7E382CCC-FC42-52FE-8D6A-6C07F958F332","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings"],"name":"Lying (Side) Quads Stretch","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs straight.","Bend your top leg and grab your ankle or foot with your hand.","Gently pull your ankle or foot towards your glutes until you feel a stretch in your quads.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"D9E2F9D1-D3D6-5E81-8D08-A029EA9F4281","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('061BEB58-7965-5CC2-8257-9FBFA7881475'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"061BEB58-7965-5CC2-8257-9FBFA7881475","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Lying Elbow To Knee","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.","At the same time, extend your right leg straight out and lift it off the ground.","Pause for a moment, then return to the starting position.","Repeat the movement, this time bringing your left elbow towards your right knee and extending your left leg.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"423ECC07-395C-52EF-B9DD-5454BD0B3E10","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('36118B9C-7D9A-502F-AABA-0ACF68B51AB3'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"36118B9C-7D9A-502F-AABA-0ACF68B51AB3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Lying Leg Raise Flat Bench","notes":"","plannedSets":3,"proTips":["Lie flat on a flat bench with your back pressed against it.","Place your hands under your glutes for support.","Keep your legs straight and together, and lift them up towards the ceiling.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3443A88A-5ACB-5E8E-BEF7-13C031E4BDF9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A918072F-FAA8-5D46-A870-608387A577BC'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A918072F-FAA8-5D46-A870-608387A577BC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Lying Leg-Hip Raise","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your core and lift your legs off the ground, raising them towards the ceiling.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A0D1EE96-51BD-5D0A-9065-D89FCD0EDB9D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C3AFF8AC-9260-531F-B04B-61AE96B4A8B7'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"C3AFF8AC-9260-531F-B04B-61AE96B4A8B7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Machine Inner Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back flat against the pad.","Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.","Push the handles forward until your arms are fully extended, exhaling during the movement.","Pause for a moment at the end of the movement, then slowly return to the starting position, inhaling as you do so.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"95FD8A40-2035-5294-ADCF-4171EAE521E2","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"866FB9CB-BCBA-5192-88A8-FB1033EFF6DE","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('09E93385-8C7E-5C5F-9E1B-7D86A413071B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"09E93385-8C7E-5C5F-9E1B-7D86A413071B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"March Sit (Wall)","notes":"","plannedSets":3,"proTips":["Stand with your back against a wall and your feet hip-width apart.","Slowly slide your back down the wall until your knees are bent at a 90-degree angle.","Lift your right foot off the ground and bring your knee towards your chest.","Lower your right foot back down and lift your left foot off the ground, bringing your knee towards your chest.","Continue alternating between lifting your right and left foot for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B59BFB5E-F0EA-5EAC-BA81-1B2206048CF7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3FD1C71A-3617-536F-80ED-51115677D050'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Medicine Ball","hint":"","id":"3FD1C71A-3617-536F-80ED-51115677D050","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Core"],"name":"Medicine Ball Catch And Overhead Throw","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a medicine ball in both hands at chest level.","Bend your knees slightly and engage your core.","Lower your body into a squat position, keeping your back straight and chest up.","Explosively extend your hips and legs, while simultaneously throwing the medicine ball overhead.","Release the ball at the top of the movement and catch it on the way down.","Lower your body back into the squat position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2D7999E7-D7AA-5451-8EDD-F686C40F08CA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('149BCBFD-69CD-56D0-B899-CC605BFB1520'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"149BCBFD-69CD-56D0-B899-CC605BFB1520","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Medicine Ball Chest Pass","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding the medicine ball at chest level.","Extend your arms forward, pushing the medicine ball away from your chest with force.","As you release the ball, follow through with your arms and torso, transferring your weight from your back foot to your front foot.","Catch the ball as it rebounds off the wall or partner, and immediately repeat the movement.","Continue for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A5553D9D-409E-5A5B-A6CB-584DEF004D44","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('20E18E00-A185-5E48-BBF1-34BA6E95910A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"20E18E00-A185-5E48-BBF1-34BA6E95910A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Medicine Ball Chest Push From 3 Point Stance","notes":"","plannedSets":3,"proTips":["Start in a 3 point stance with one hand on the medicine ball and the other hand on the ground.","Extend your legs and position your body in a straight line.","Lower your chest towards the ground while keeping your back straight.","Push the medicine ball away from your body, extending your arm fully.","Return to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0A10C1F8-194A-5D11-9F74-4F12505EFB82","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('225D35FB-8FE5-5D06-BDCD-5F97B419E1B1'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"225D35FB-8FE5-5D06-BDCD-5F97B419E1B1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Medicine Ball Chest Push Multiple Response","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a medicine ball at chest level.","Extend your arms forward, pushing the medicine ball away from your chest.","Pause for a moment, then slowly bring the medicine ball back to your chest.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"500A6738-D19B-547D-84C7-CDA39D53D1C0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CB4C01F1-1568-5839-80ED-0A7B0FEED81C'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"CB4C01F1-1568-5839-80ED-0A7B0FEED81C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Medicine Ball Chest Push Single Response","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding the medicine ball at chest level.","Extend your arms forward, pushing the medicine ball away from your chest.","Pause for a moment, then slowly bring the medicine ball back to your chest.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B65FED84-639F-5A26-9B1B-F26069E332FD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C556DD76-68CB-5B08-B40E-63E87ADF6D94'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"C556DD76-68CB-5B08-B40E-63E87ADF6D94","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Medicine Ball Chest Push With Run Release","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a medicine ball at chest level.","Step forward with your right foot and simultaneously push the medicine ball forward, extending your arms fully.","As you push the ball forward, release it and let it roll forward.","Quickly run forward and catch the ball before it hits the ground.","Once you catch the ball, bring it back to your chest and repeat the movement with your left foot forward.","Continue alternating legs and repeating the exercise for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CF5353E8-7F80-521F-BFEA-6306DF2FD7F0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('478AED99-B9A6-50FA-A10E-774C3C647B41'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"478AED99-B9A6-50FA-A10E-774C3C647B41","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Medicine Ball Close Grip Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands on the medicine ball, shoulder-width apart.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Push back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CB6762AD-15A1-59EB-8AD6-2390CE14CC11","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D78AF747-4416-5394-8C1D-488D740F3D68'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Medicine Ball","hint":"","id":"D78AF747-4416-5394-8C1D-488D740F3D68","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Core"],"name":"Medicine Ball Overhead Slam","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a medicine ball with both hands above your head.","Engage your core and keep your back straight.","Bend your knees slightly and forcefully slam the medicine ball down to the ground in front of you.","As you slam the ball down, use your entire body to generate power, including your shoulders and core.","Catch the ball on the bounce and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AFD47EFC-9C7B-502D-9B04-214B41F78805","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A9AB9948-1666-52CD-BB26-60D18EB73AEF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"A9AB9948-1666-52CD-BB26-60D18EB73AEF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Medicine Ball Supine Chest Throw","notes":"","plannedSets":3,"proTips":["Lie flat on your back on a bench with your knees bent and feet flat on the ground.","Hold the medicine ball with both hands, extending your arms straight up above your chest.","Lower the medicine ball towards your chest, keeping your elbows close to your body.","Explosively push the medicine ball upwards, extending your arms fully and throwing the ball as high as possible.","Catch the medicine ball and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"753D48D1-09CA-5DD6-B363-DF858E927ADA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D00B0F69-E51A-5DA6-9A30-06C0F729E082'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D00B0F69-E51A-5DA6-9A30-06C0F729E082","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Mixed Grip Chin-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with an underhand grip (palms facing towards you) and your hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"641287B6-D5E3-5A62-9976-FFCE8EECD7FD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5B48ED99-72CA-51DB-B344-ABA26D8C0569'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5B48ED99-72CA-51DB-B344-ABA26D8C0569","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Modified Hindu Push-Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet hip-width apart.","Lower your body towards the ground, bending your elbows and keeping your core engaged.","As you lower your body, shift your weight back and lift your hips up towards the ceiling, creating an inverted V shape with your body.","Continue to lower your body until your chest is just above the ground, then reverse the movement, pushing your hips back down and extending your arms to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D114B92D-ECFB-5EBA-8653-70F0B338DFCE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5D439293-9A1F-504E-812B-38623C5B06BF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5D439293-9A1F-504E-812B-38623C5B06BF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Triceps","Chest","Shoulders"],"name":"Modified Push Up To Lower Arms","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands directly under your shoulders and your body in a straight line.","Lower your body down towards the ground by bending your elbows, keeping them close to your sides.","Once your elbows are at a 90-degree angle, lower your forearms to the ground, keeping your elbows directly under your shoulders.","Pause for a moment, then push through your palms to lift your forearms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A65E08B2-8047-508C-AC5F-9A2E91A2C49C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AEF2C4AD-F098-55B8-95D2-AF6CE8DE251F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AEF2C4AD-F098-55B8-95D2-AF6CE8DE251F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Monster Walk","notes":"","plannedSets":3,"proTips":["Place a resistance band around your ankles.","Stand with your feet shoulder-width apart and slightly bend your knees.","Take a step to the side with your right foot, maintaining tension on the resistance band.","Follow with your left foot, stepping to the side to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F47C292B-6432-59BA-B07B-40D8467C620C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('12FFCB9E-6C45-5205-B299-9F10DD92E1B2'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"12FFCB9E-6C45-5205-B299-9F10DD92E1B2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Core","Shoulders","Triceps"],"name":"Mountain Climber","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest.","Continue alternating legs in a running motion, keeping your hips low and your core engaged.","Maintain a steady pace and breathe evenly throughout the exercise.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('68D64911-96FD-50B3-ABF7-C404FCB4B106'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"68D64911-96FD-50B3-ABF7-C404FCB4B106","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Triceps","Shoulders","Chest"],"name":"Muscle Up","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.","Engage your core and pull your body up towards the bar, leading with your chest.","As you reach the top of the movement, transition your grip so that your palms are facing towards you.","Continue pulling yourself up until your chest is above the bar and your arms are fully flexed.","Reverse the movement by slowly lowering yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7C727AFF-9A67-56D7-AF86-8D34116E8C34","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CBB43F5A-D2BD-5729-A524-AE6A1A1F105C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CBB43F5A-D2BD-5729-A524-AE6A1A1F105C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Triceps","Forearms"],"name":"Muscle-Up (On Vertical Bar)","notes":"","plannedSets":3,"proTips":["Start by hanging from a vertical bar with your palms facing away from you and your arms fully extended.","Engage your core and pull your body up towards the bar, leading with your chest.","As you pull yourself up, lean back slightly and bring your elbows towards your sides.","Continue pulling until your chest reaches the bar and your elbows are fully bent.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ACD6706F-C1FE-5358-99E6-841D2FC65D69","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F2691775-A14D-5110-999E-A24A349C3F3C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"F2691775-A14D-5110-999E-A24A349C3F3C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Narrow Push-Up On Exercise Ball","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and position yourself in a push-up position with your hands on the ball, slightly narrower than shoulder-width apart.","Engage your core and keep your body in a straight line from head to toe.","Lower your chest towards the ball by bending your elbows, keeping them close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1D3405DE-28C9-547A-BA37-6ECCAF40E1FF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('89FB097C-3DBC-5567-8521-E371F66F8208'::uuid, '{"category":"Neck","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"89FB097C-3DBC-5567-8521-E371F66F8208","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Levator Scapulae","Trapezius","Sternocleidomastoid"],"name":"Neck Side Stretch","notes":"","plannedSets":3,"proTips":["Stand or sit up straight with your shoulders relaxed.","Tilt your head to one side, bringing your ear towards your shoulder.","Hold the stretch for 15-30 seconds.","Repeat on the other side.","Perform 2-4 sets on each side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"1EE82012-87D3-5E72-A7B7-D414CFDD7856","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('3043E6AD-AAE1-540C-A1C2-840E16138CCB'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3043E6AD-AAE1-540C-A1C2-840E16138CCB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Negative Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F2910D66-B961-5217-B305-D5322601A325","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('06601432-62DF-5960-8EEB-7E8513559058'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"06601432-62DF-5960-8EEB-7E8513559058","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Oblique Crunch V. 2","notes":"","plannedSets":3,"proTips":["Lie on your back with your knees bent and feet flat on the ground.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your shoulder blades off the ground, rotating your torso to one side.","Pause for a moment, then lower your shoulder blades back down to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DA60E631-9778-50DC-8B70-42E87CCAE6D2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('58CD75C5-F439-5FD8-88A8-305931901D89'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"58CD75C5-F439-5FD8-88A8-305931901D89","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Oblique Crunches Floor","notes":"","plannedSets":3,"proTips":["Lie on your back with your knees bent and feet flat on the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side.","Pause for a moment, then lower your shoulder blades back down to the floor.","Repeat on the other side, alternating sides with each repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"703C5821-7C06-586F-BB32-2CB99B0DB3C9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DC374608-FBE1-57EE-BFCD-7A6681E4B6CA'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"DC374608-FBE1-57EE-BFCD-7A6681E4B6CA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Olympic Barbell Hammer Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold an Olympic barbell with an overhand grip.","Let the barbell hang at arm''s length in front of your thighs, with your palms facing your body.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A01BFD41-17A0-56A8-8533-7134758FF987","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B664DB0C-E73B-5AFD-B847-DBCDD2EA75D8","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4D059DA6-F6C7-5C03-B846-9F6B94E59250","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4AD909FA-ADE4-57F4-A5C9-B0A48CD89283","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F46E6FA5-7B8E-574C-ABA9-811AC44BDD20'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"F46E6FA5-7B8E-574C-ABA9-811AC44BDD20","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Olympic Barbell Triceps Extension","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and holding the barbell with an overhand grip.","Raise the barbell above your head, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9CC1AD98-B70D-5CAA-BFC4-862267CAE62B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A193F5B0-43C7-53BB-9175-5D33CFA604EA","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"353C353B-420B-53FE-AE51-1D874BAA3C5F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E625FBC0-B4FB-5E6A-A013-94C958D82FB8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9415594D-F2D5-5B1A-9A8E-886E77FEEA76'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9415594D-F2D5-5B1A-9A8E-886E77FEEA76","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Triceps"],"name":"One Arm Against Wall","notes":"","plannedSets":3,"proTips":["Stand facing a wall with your feet shoulder-width apart.","Extend one arm straight out in front of you and place your palm against the wall.","Engage your core and lean your body forward, keeping your arm straight and your back flat.","Slowly push against the wall with your palm, activating your lat muscles.","Hold the position for a few seconds, then release and repeat with the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FECAB323-BAFD-5E72-A3CB-41036B9DD2DE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('267D35BD-988B-5978-AEAD-6FDF281DF78E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"267D35BD-988B-5978-AEAD-6FDF281DF78E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"One Arm Chin-Up","notes":"","plannedSets":3,"proTips":["Stand facing a pull-up bar with your feet shoulder-width apart.","Reach up and grab the bar with an underhand grip, with one hand gripping the bar and the other hand holding your wrist for support.","Hang from the bar with your arm fully extended, keeping your body straight and your core engaged.","Pull yourself up towards the bar by bending your elbow and squeezing your back muscles.","Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6F180C9E-1C86-575E-8E98-07BF8D68603F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9EF6C9C9-0229-5785-8400-D24B1E1900AF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9EF6C9C9-0229-5785-8400-D24B1E1900AF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"One Arm Dip","notes":"","plannedSets":3,"proTips":["Stand facing away from a bench or chair, with your feet shoulder-width apart.","Place one hand on the bench or chair behind you, fingers pointing towards your body.","Extend your legs out in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair.","Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat with the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"187C8EE6-3144-5BED-9351-5ECF4D926543","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0C1F66B9-B427-544B-BC77-E7AF0BCAF7B4'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"0C1F66B9-B427-544B-BC77-E7AF0BCAF7B4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Back"],"name":"One Arm Slam (With Medicine Ball)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding the medicine ball with one hand in front of your waist.","Bend your knees slightly and engage your core.","Raise the medicine ball above your head, fully extending your arm.","Forcefully slam the medicine ball down to the ground, using your core and shoulders to generate power.","Catch the medicine ball on the bounce and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1614124D-B7DF-55EA-B48A-E17B0C0D1E08","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('06CE53BC-58B9-5507-AF1C-75C388A6E496'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"06CE53BC-58B9-5507-AF1C-75C388A6E496","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"One Arm Towel Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arm fully, allowing the towel to hang in front of you.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0D597783-5FBC-58DB-BBCA-DA2CF5F0EBEC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BCFFCB3D-41B7-5605-BA7D-AF6738A850CE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"BCFFCB3D-41B7-5605-BA7D-AF6738A850CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"One Leg Donkey Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a stable surface for support, such as a wall or a bar.","Lift one leg off the ground, keeping your knee slightly bent.","Raise your heel as high as possible, using your calf muscles.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3E027ACF-AE56-542D-95AF-A46436313D9A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1F42840D-5E15-560E-874A-9F6A275A866D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1F42840D-5E15-560E-874A-9F6A275A866D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"One Leg Floor Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and place your hands on a wall or sturdy object for balance.","Lift one foot off the ground and balance on the other foot.","Slowly raise your heel off the ground, lifting your body up onto the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F9B16A65-06FC-5E8C-8033-7364C4CABF38","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('80DC6E0F-F5FB-594B-8C35-2BCACBDF7B3E'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"80DC6E0F-F5FB-594B-8C35-2BCACBDF7B3E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"One Leg Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Extend one leg forward, keeping it off the ground.","Bend your standing leg and lower your body down as if sitting back into a chair.","Keep your chest up and your back straight.","Push through your heel to return to the starting position.","Repeat with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"85E6F89A-1142-5060-93C0-0D637D3D45BD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D4D127D1-8FDC-5968-845C-FA71451E5AA0'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D4D127D1-8FDC-5968-845C-FA71451E5AA0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Otis Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"835E27E9-D164-5441-B70A-586D48EB782B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F7F81785-5CF2-5463-A464-103B6F52BA62'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F7F81785-5CF2-5463-A464-103B6F52BA62","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Outside Leg Kick Push-Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.","As you push back up, kick one leg out to the side, extending it fully and engaging your glutes.","Return your leg to the starting position and repeat the push-up, alternating legs with each repetition.","Continue alternating leg kicks and push-ups for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A76C89E9-6D08-54C2-BBB0-A6294C3A42DA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('29865F6D-B51A-5202-B200-D8F76B4BC116'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Bodyweight","hint":"","id":"29865F6D-B51A-5202-B200-D8F76B4BC116","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Overhead Triceps Stretch","notes":"","plannedSets":3,"proTips":["Stand or sit upright with your feet shoulder-width apart.","Extend one arm overhead, bending at the elbow so that your hand reaches towards the opposite shoulder blade.","With your other hand, gently pull the elbow of the extended arm towards the opposite side of your head, feeling a stretch in your triceps.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"FA8C9519-D908-56E0-A6F7-3740590DE0FE","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('271AC105-CC91-504E-8F8B-E0314D581CDE'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"271AC105-CC91-504E-8F8B-E0314D581CDE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Lower Back"],"name":"Pelvic Tilt","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides.","Engage your abs and tilt your pelvis upward, pressing your lower back into the ground.","Hold this position for a few seconds, focusing on contracting your abs.","Release the tilt and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6DC24C0C-01F7-56C9-BB5C-E2AA2A5056AA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('121F3C3B-E150-591F-87FF-489D848E801D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"121F3C3B-E150-591F-87FF-489D848E801D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Core"],"name":"Pelvic Tilt Into Bridge","notes":"","plannedSets":3,"proTips":["Lie on your back with your knees bent and feet flat on the ground.","Place your arms by your sides with your palms facing down.","Engage your glutes and core muscles.","Tilt your pelvis upward, lifting your hips off the ground.","Hold the bridge position for a few seconds.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"056785AB-4124-53CA-A05B-20AAC36036AD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('983F961B-4BE0-5CDB-95F4-00979559B367'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Rope","hint":"","id":"983F961B-4BE0-5CDB-95F4-00979559B367","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Peroneals Stretch","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Loop the rope around the ball of your foot and hold the ends of the rope with your hands.","Gently pull the rope towards you, flexing your foot and stretching your calf muscles.","Hold the stretch for 15-30 seconds.","Release the tension on the rope and repeat the stretch on the other leg.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"6343536E-FE87-5184-8513-F403D3AD918D","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('95DEA9A8-89BC-5A74-9D0D-A2504CED211E'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"95DEA9A8-89BC-5A74-9D0D-A2504CED211E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Core","Shoulders","Triceps"],"name":"Pike-To-Cobra Push-Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lift your hips up towards the ceiling, forming an inverted V shape with your body.","Lower your upper body towards the ground by bending your elbows, keeping them close to your body.","As you lower down, shift your weight forward and transition into a cobra pose by straightening your arms and lifting your chest up.","Reverse the movement by bending your elbows and lowering your chest back down towards the ground.","Push through your hands to return to the inverted V position.","Continue the movement by lowering your hips back down towards the ground, returning to the starting push-up position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E556DBF2-1439-514C-A94E-FF28905FC700","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9B6CFEA0-3E4F-5501-9733-519A7B33EBA3'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9B6CFEA0-3E4F-5501-9733-519A7B33EBA3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Plyo Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground by bending your elbows, keeping your body in a straight line.","Push explosively off the ground, using your chest muscles to propel your upper body off the ground.","Land softly with your hands back in the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99AF6A5E-F20C-5302-B66C-4197569219FC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ACC1F0A2-7127-55BF-8516-06053A39B51A'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Bodyweight","hint":"","id":"ACC1F0A2-7127-55BF-8516-06053A39B51A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Glutes","Hamstrings","Quadriceps","Shoulders"],"name":"Posterior Step To Overhead Reach","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and your arms by your sides.","Take a step back with your right foot, landing on the ball of your foot.","Bend your left knee and lower your body into a lunge position.","As you lower into the lunge, simultaneously reach your arms overhead.","Pause for a moment at the bottom of the lunge, then return to the starting position by pushing through your left heel and bringing your right foot forward.","Repeat the movement on the other side, stepping back with your left foot and bending your right knee.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AEA5F8FD-40E5-5076-971B-099D76CEFE72","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8FEF6429-1084-5EC1-9604-F851AF6053CF'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Rope","hint":"","id":"8FEF6429-1084-5EC1-9604-F851AF6053CF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Posterior Tibialis Stretch","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Loop the rope around the ball of your foot and hold the ends of the rope with your hands.","Gently pull the rope towards you, flexing your foot and stretching your calf muscles.","Hold the stretch for 20-30 seconds.","Release the tension on the rope and relax your foot.","Repeat the stretch on the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"C12A2341-0B58-567E-83E7-B88287C03B3A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('9FEB7AD6-4A1D-5376-A62A-9EB05A90B65B'::uuid, '{"category":"Core","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"9FEB7AD6-4A1D-5376-A62A-9EB05A90B65B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Quadriceps","Glutes"],"name":"Potty Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Lower your body down by bending your knees and pushing your hips back as if you were sitting on a chair.","Keep your chest up and your back straight throughout the movement.","Lower yourself until your thighs are parallel to the ground or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2CC77165-7AC8-555A-A6FF-2DF3B6A0FBCB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('38DA457E-7DBB-5B9C-B8B1-3ECC5E8AE5AD'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"38DA457E-7DBB-5B9C-B8B1-3ECC5E8AE5AD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Potty Squat With Support","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Hold onto a stable support, such as a chair or wall, for balance.","Lower your body down into a squat position by bending your knees and pushing your hips back.","Keep your chest up and your back straight throughout the movement.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F9AA6FCE-D776-5177-9DD0-ED1F06A6F589","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3DF7EE7B-017C-5A8D-BD37-A16916687D03'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"3DF7EE7B-017C-5A8D-BD37-A16916687D03","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Quadriceps","Calves"],"name":"Power Clean","notes":"","plannedSets":3,"proTips":["Start with the barbell on the ground in front of you, with your feet shoulder-width apart.","Bend down and grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and chest up as you lift the barbell off the ground, extending your hips and knees.","As the barbell reaches your mid-thigh, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.","As the barbell reaches its highest point, quickly drop underneath it, rotating your elbows around and catching the barbell on your shoulders in a front squat position.","Stand up with the barbell, fully extending your hips and knees.","Lower the barbell back down to the starting position, keeping control of the weight throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E2A55B1A-B2BC-5905-A7D3-276332039432","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B584C7E4-1C35-565D-8051-4AD6614468B1","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"DFACA663-3F13-5CC1-84A2-0C6CDC2FC9D4","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"6B8FBFEF-7057-5D53-A196-3E90F231B9A4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9815A177-51AC-5F6A-92A0-A7518E025349'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9815A177-51AC-5F6A-92A0-A7518E025349","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps","Glutes"],"name":"Power Point Plank","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.","Engage your core and squeeze your glutes to maintain a stable position.","Lower your body down onto your forearms, one arm at a time, maintaining a straight line from head to toe.","Hold this position for the desired amount of time, keeping your core and glutes engaged.","To return to the starting position, push through your forearms and lift your body back up into a high plank position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3F8FE7B2-B012-52A7-9925-285D5DEE048A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D38EFFD8-335F-5324-8AE8-6803B03B9A96'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D38EFFD8-335F-5324-8AE8-6803B03B9A96","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Prisoner Half Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"827C1D36-B027-566F-B521-E132F593D715","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9EF71955-9903-5618-8A82-65FB4293385D'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"9EF71955-9903-5618-8A82-65FB4293385D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Prone Twist On Stability Ball","notes":"","plannedSets":3,"proTips":["Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground.","Place your hands behind your head or cross them over your chest.","Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight.","Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement.","Pause for a moment, then return to the starting position.","Repeat the rotation to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"01773BD4-A478-5838-ABEC-24775DFF9757","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D9797AA6-19B4-5C90-959F-0CB0D7CE43A1'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D9797AA6-19B4-5C90-959F-0CB0D7CE43A1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Pull Up (Neutral Grip)","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with a neutral grip (palms facing each other) and your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar by bending your elbows and driving your elbows down towards your hips.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"45561230-4B4B-5F04-805A-A5844F1E13B0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('198FFB8F-A380-5F65-B214-9EEDC3A29805'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"198FFB8F-A380-5F65-B214-9EEDC3A29805","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Pull-In (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Start by sitting on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands on the sides of the stability ball for support.","Engage your abs and slowly roll your hips forward, bringing your knees towards your chest.","Pause for a moment at the top of the movement, then slowly extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"962206E9-AF42-581A-92F8-289F47EE3013","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4F11B5C8-D107-5467-BC5C-AD4C2C589842'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"4F11B5C8-D107-5467-BC5C-AD4C2C589842","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Pull-Up","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your palms facing away from you and your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B53748EF-4031-5804-8E53-B5E2E462C955","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F0588549-AEEE-5E35-A335-43DEB2940A38'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F0588549-AEEE-5E35-A335-43DEB2940A38","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Deltoids"],"name":"Push And Pull Bodyweight","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping your body straight.","Push through your palms to extend your arms and return to the starting position.","From the push-up position, pull your chest towards the ground by bending your elbows, keeping your body straight.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"65635CA3-44AA-56DF-B6B8-47D379C58CA1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6B3308F3-CE7F-5EF5-B023-12DD19485DDC'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6B3308F3-CE7F-5EF5-B023-12DD19485DDC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Push To Run","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping your body straight.","Push through your hands to extend your arms and return to the starting position.","Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest.","Continue alternating knees as fast as you can while maintaining good form.","Continue for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('9A35DD7B-C1A9-50E7-9651-2CED86C167C0'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bosu Ball","hint":"","id":"9A35DD7B-C1A9-50E7-9651-2CED86C167C0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Push Up On BOSU Ball","notes":"","plannedSets":3,"proTips":["Place the bosu ball on the ground with the flat side facing up.","Position yourself in a push-up position with your hands on the outer edges of the bosu ball.","Engage your core and lower your body down towards the bosu ball by bending your elbows.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3A674494-D0B5-5F02-B581-8DBADF6C4B08","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3CB51C5F-1C5E-58F5-9477-FE3F2189F027'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3CB51C5F-1C5E-58F5-9477-FE3F2189F027","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Deltoids","Core"],"name":"Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line.","Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1F3B8209-4B7F-52EA-BDD4-71B70808985F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5FC72531-F821-55CC-BAE3-FF267011C4BE'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bosu Ball","hint":"","id":"5FC72531-F821-55CC-BAE3-FF267011C4BE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Push-Up (BOSU Ball)","notes":"","plannedSets":3,"proTips":["Place the bosu ball on the ground with the flat side facing up.","Position yourself in a push-up position with your hands on the outer edges of the bosu ball.","Engage your core and lower your body down towards the bosu ball by bending your elbows.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E97E6362-07D1-5E0B-85E1-A79EAD499B31","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6402A149-4350-534D-B952-9A65F770631D'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"6402A149-4350-534D-B952-9A65F770631D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Push-Up (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.","Extend your legs straight out behind you, balancing on your toes.","Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"645FA751-632E-546D-9098-66FD5EF79387","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A7B39724-7831-5E22-8C18-615EEDF93748'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A7B39724-7831-5E22-8C18-615EEDF93748","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Deltoids"],"name":"Push-Up (Wall)","notes":"","plannedSets":3,"proTips":["Stand facing a wall, about arm''s length away.","Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.","Step back a few feet, keeping your body straight and your feet hip-width apart.","Bend your elbows and lower your chest towards the wall, keeping your body in a straight line.","Push back up to the starting position, straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F59584B8-2A2B-56CF-886E-DABE8918B870","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2F716C3B-7C8D-5F39-A9E9-7982431A1CC2'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2F716C3B-7C8D-5F39-A9E9-7982431A1CC2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Push-Up (Wall) V. 2","notes":"","plannedSets":3,"proTips":["Stand facing a wall, about arm''s length away.","Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.","Step back with your feet, keeping them hip-width apart.","Engage your core and keep your body in a straight line from head to heels.","Bend your elbows and lower your chest towards the wall, keeping your body straight.","Pause for a moment, then push yourself back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0E249968-BC38-5801-AA16-707B8BA344F3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F8E2E9AB-3166-57D9-9518-7C0A0EA41119'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F8E2E9AB-3166-57D9-9518-7C0A0EA41119","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Push-Up Close-Grip Off Dumbbell","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands placed close together, directly under your shoulders.","Hold a dumbbell in each hand, resting them on the ground.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BBA55F94-410F-5E0C-9EED-6A0F205F0769","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0966CE7F-9D75-5D0C-913F-A83546938A11'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0966CE7F-9D75-5D0C-913F-A83546938A11","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Push-Up Inside Leg Kick","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your body towards the ground by bending your elbows, keeping your back straight and your core engaged.","As you push back up, lift one leg off the ground and kick it out to the side, keeping it straight.","Lower your leg back down and repeat the push-up, then switch to the other leg.","Continue alternating leg kicks with each push-up repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BE5AFA6F-92E5-5E5D-8D18-E2C95EC9C8F5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('65CD1118-6B0E-542F-B612-89A42A9299F6'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"65CD1118-6B0E-542F-B612-89A42A9299F6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Push-Up Medicine Ball","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands on the medicine ball, shoulder-width apart.","Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9DE3EE53-A26A-5383-B4DF-C4BE89100545","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A373F829-B08B-57F6-AF4B-2044190A9BFE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A373F829-B08B-57F6-AF4B-2044190A9BFE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Push-Up On Lower Arms","notes":"","plannedSets":3,"proTips":["Start in a plank position with your forearms on the ground and elbows directly below your shoulders.","Engage your core and keep your body in a straight line from head to toe.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9DA29990-3782-5459-9EE7-091F37E6D3FC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F2FAA121-2FDF-53F3-BD9E-97955DBE4198'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F2FAA121-2FDF-53F3-BD9E-97955DBE4198","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Push-Up Plus","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up.","At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling.","Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FDDDE210-784C-5B37-8DD8-5D372C5B3DA6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4879C33C-262E-530F-914A-8E2351DBDF39'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"4879C33C-262E-530F-914A-8E2351DBDF39","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest","Triceps"],"name":"Push-Up To Side Plank","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push back up to the starting position.","Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling.","Hold the side plank position for a few seconds, then return to the starting position.","Repeat the push-up and side plank on the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FDC6367B-1F87-5431-9792-D6BAA7A50ED3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C31F9ACE-EC76-5035-9269-1998CDB6BBBD'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C31F9ACE-EC76-5035-9269-1998CDB6BBBD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes"],"name":"Quads","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Lower your body by bending your knees and pushing your hips back as if sitting on a chair.","Keep your chest up and your back straight.","Lower yourself until your thighs are parallel to the ground.","Push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"21B4DD39-EA19-52E7-BB15-5978DD0E719F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8506DB9C-A8F8-5D87-A9D7-813B71C5E887'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8506DB9C-A8F8-5D87-A9D7-813B71C5E887","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Quarter Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0C976055-945B-5CF3-94EE-0ADF9A2D6BA6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CF14FC3E-8B70-5E7D-A831-62BB2611FF00'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CF14FC3E-8B70-5E7D-A831-62BB2611FF00","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Calves","Hamstrings"],"name":"Quick Feet V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms by your sides.","Begin by rapidly moving your feet up and down, as if you were running in place.","Keep your movements quick and light, focusing on staying on the balls of your feet.","Continue for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BBFB346F-E282-5155-873D-29256A7623A2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E9EE9C97-944C-5E9C-B388-AFC4A8855D69'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E9EE9C97-944C-5E9C-B388-AFC4A8855D69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Raise Single Arm Push-Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Extend one arm straight out to the side, parallel to the ground.","Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position, using your chest muscles to lift your body.","Repeat with the other arm extended."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AF123147-3853-53F3-8FD6-47EAE3DCB4E8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9123E05D-59C2-5531-882D-F0004EBB7537'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9123E05D-59C2-5531-882D-F0004EBB7537","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Rear Decline Bridge","notes":"","plannedSets":3,"proTips":["Lie on your back with your feet flat on the ground and your knees bent.","Place your arms by your sides with your palms facing down.","Engage your glutes and hamstrings, and lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Hold this position for a few seconds, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4E0B79E6-6403-5CAB-9E82-C05857E3A0CB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('05AC2BA3-DB46-54A0-9FA9-0F118DCAABFE'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"05AC2BA3-DB46-54A0-9FA9-0F118DCAABFE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Rear Deltoid Stretch","notes":"","plannedSets":3,"proTips":["Stand tall with your feet shoulder-width apart.","Extend your right arm across your chest, placing your left hand on your right elbow.","Gently pull your right arm towards your left shoulder, feeling a stretch in your right shoulder.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"AEBBDCB4-CA5A-580D-BABC-E79F37D7A99B","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('D4F42A6E-6E79-5E74-B6D6-0E68DE4B0C85'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D4F42A6E-6E79-5E74-B6D6-0E68DE4B0C85","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Rear Pull-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"94D5BC6F-C19D-5D66-A71D-A083A851FACC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D92113C3-7E03-56C6-B180-29CEA8E128BD'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Rope","hint":"","id":"D92113C3-7E03-56C6-B180-29CEA8E128BD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Calves","Glutes"],"name":"Reclining Big Toe Pose With Rope","notes":"","plannedSets":3,"proTips":["Lie on your back with your legs extended and your arms by your sides.","Loop the rope around the ball of your right foot and hold the ends of the rope with your hands.","Slowly raise your right leg towards your chest, keeping your knee straight and your foot flexed.","Hold the stretch for a few seconds, then slowly lower your leg back down to the starting position.","Repeat with your left leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A0C10EF6-FCCE-5322-A910-7F9ED194F2F2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F50A8240-438F-5FC7-84C1-A5D29CF4C37C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"F50A8240-438F-5FC7-84C1-A5D29CF4C37C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Resistance Band Hip Thrusts On Knees","notes":"","plannedSets":3,"proTips":["Start by kneeling on the ground with your knees hip-width apart and your feet flexed.","Wrap the resistance band around your thighs, just above your knees.","Place your hands on your hips or extend them out in front of you for balance.","Engage your glutes and core muscles.","Push your hips forward and squeeze your glutes as you lift your knees off the ground, extending your hips until your thighs are parallel to the ground.","Hold the position for a moment, then slowly lower your knees back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"25A608C3-2CC5-525C-A221-91D9C8DD7B34","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3357ADD7-ED2B-5F1D-BB64-A1FC70FC4E37'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"3357ADD7-ED2B-5F1D-BB64-A1FC70FC4E37","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings"],"name":"Resistance Band Leg Extension","notes":"","plannedSets":3,"proTips":["Attach the resistance band to a sturdy anchor point and secure it around your ankle.","Stand facing the anchor point with your feet shoulder-width apart.","Keeping your core engaged and your upper body stable, extend your leg straight out in front of you.","Pause for a moment at the top, then slowly return your leg to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"883487CA-26F1-5A11-A44A-E5AA262E747D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F09AA556-882C-5103-BE09-F520686347D8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"F09AA556-882C-5103-BE09-F520686347D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Resistance Band Seated Biceps Curl","notes":"","plannedSets":3,"proTips":["Sit on a chair or bench with your back straight and feet flat on the ground.","Hold the resistance band with an underhand grip, palms facing up, and arms extended down by your sides.","Keeping your upper arms stationary, exhale and curl the resistance band up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the resistance band back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"703F65E7-CC80-50F7-9670-8083BFDE7373","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35882645-456E-5E6F-8D18-D380C6E676B9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Band","hint":"","id":"35882645-456E-5E6F-8D18-D380C6E676B9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Resistance Band Seated Chest Press","notes":"","plannedSets":3,"proTips":["Sit on a chair or bench with your back straight and feet flat on the ground.","Hold the resistance band handles in each hand, with your palms facing down and elbows bent at a 90-degree angle.","Extend your arms forward, pushing the resistance band away from your chest.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E8C442E0-17D2-5BD9-9D54-D154A6069567","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D83DC222-EF06-5493-8A42-BA12C7D5CD50'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"D83DC222-EF06-5493-8A42-BA12C7D5CD50","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abductors","Glutes","Hamstrings"],"name":"Resistance Band Seated Hip Abduction","notes":"","plannedSets":3,"proTips":["Sit on a chair or bench with your back straight and feet flat on the ground.","Wrap the resistance band around your thighs, just above your knees.","Place your hands on the sides of the chair or bench for support.","Engage your abductors (outer thigh muscles) and slowly push your knees apart, against the resistance of the band.","Pause for a moment at the end of the movement, then slowly bring your knees back together.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FF21E90A-46A9-5E71-A5A9-B932464B7443","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('769459B6-6EB9-598F-B42A-1FBB38FDA2D3'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"769459B6-6EB9-598F-B42A-1FBB38FDA2D3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Resistance Band Seated Shoulder Press","notes":"","plannedSets":3,"proTips":["Sit on a chair or bench with your back straight and feet flat on the ground.","Hold the resistance band with both hands, palms facing forward, and bring it up to shoulder level.","Press the band overhead, extending your arms fully.","Pause for a moment at the top, then slowly lower the band back down to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"137B27A0-65B9-5CA1-B5EC-C94D8FFA4DB7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3C45A92D-7F0C-50D3-875A-284D0AC05BFA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"3C45A92D-7F0C-50D3-875A-284D0AC05BFA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Resistance Band Seated Straight Back Row","notes":"","plannedSets":3,"proTips":["Sit on the floor with your legs extended and loop the resistance band around your feet.","Hold the ends of the resistance band with your hands, palms facing each other.","Keep your back straight and lean slightly back, engaging your core.","Pull the resistance band towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"83CEE580-0FBD-5431-B827-AE593F72F93A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BA4DBE7A-DFF4-5EB5-8B80-C67DB828F3C2'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"BA4DBE7A-DFF4-5EB5-8B80-C67DB828F3C2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Reverse Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your arms extended along your sides.","Bend your knees and lift your feet off the ground, bringing your thighs perpendicular to the floor.","Contract your abs and curl your hips off the floor, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"384F694B-E9CE-595F-AAD2-DFF1B5F639AE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CB886754-DF62-54B1-B9A4-BA6E30DB5293'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CB886754-DF62-54B1-B9A4-BA6E30DB5293","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Reverse Dip","notes":"","plannedSets":3,"proTips":["Position yourself between two parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6FD7CAA6-3E57-5B1B-A566-2A849F395DD9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A2F6ADBC-648C-5128-A463-1449E89666A5'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"A2F6ADBC-648C-5128-A463-1449E89666A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Reverse Grip Machine Lat Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.","Grasp the handles with an underhand grip, slightly wider than shoulder-width apart.","Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back.","Pull the handles down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B4D1FC7E-40C3-541C-B425-E709357282ED","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"FB654D4E-D9AB-5622-9DD4-5B0443F6E611","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('765875A3-4E0A-543E-993E-610CA54351EB'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"765875A3-4E0A-543E-993E-610CA54351EB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Reverse Grip Pull-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with an underhand grip, hands shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5CA9441F-ED09-50B3-9E45-E42C5194293A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('24022F5B-BE67-5D9E-847F-87B6B372CC1B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"24022F5B-BE67-5D9E-847F-87B6B372CC1B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Reverse Hyper Extension (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Lie face down on a stability ball with your hips resting on the ball and your legs extended straight behind you.","Place your hands on the ground in front of you for stability.","Engaging your glutes and hamstrings, lift your legs up towards the ceiling as high as you can.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0604E2A5-1838-5A89-940C-A80F4BBE68C0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('96A87025-D7AF-54D4-8E7C-19543ABECCDC'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"96A87025-D7AF-54D4-8E7C-19543ABECCDC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Reverse Hyper On Flat Bench","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with your hips at the edge and your legs hanging off the bench.","Hold onto the bench for stability.","Keeping your legs straight, raise them up towards the ceiling as high as you can.","Squeeze your glutes at the top of the movement.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ECC08BAE-4FA6-5004-BC84-86082D1E95D9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4CAC8A45-514B-59D0-BDD5-6B890EF4ABDB'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"4CAC8A45-514B-59D0-BDD5-6B890EF4ABDB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Glutes","Hamstrings","Shoulders"],"name":"Reverse Plank With Leg Lift","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you and your hands resting on the ground behind you, fingers pointing towards your feet.","Press through your hands and lift your hips off the ground, coming into a reverse plank position.","Engage your core and lift one leg off the ground, extending it straight up towards the ceiling.","Hold for a moment, then lower your leg back down.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8BA8BBAD-E7F4-52B7-99BF-B5BEB49D8090","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B3783725-1091-5CA4-948A-58149F7C6F76'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B3783725-1091-5CA4-948A-58149F7C6F76","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Ring Dips","notes":"","plannedSets":3,"proTips":["Start by hanging from the rings with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6BD7A7DA-D9C4-5507-B3D0-33DD96328176","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('18910A44-6B1E-5419-9B8C-85DAC7CE4EAB'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"18910A44-6B1E-5419-9B8C-85DAC7CE4EAB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Rocking Frog Stretch","notes":"","plannedSets":3,"proTips":["Start by kneeling on the ground with your knees hip-width apart.","Place your hands on the ground in front of you for support.","Slowly lean forward, shifting your weight onto your hands and extending your legs behind you.","Keep your back straight and engage your glutes as you push your hips back and up towards the ceiling.","Hold this position for a few seconds, feeling a stretch in your glutes.","Slowly return to the starting position by bending your knees and lowering your hips back down.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"3EA6D505-F0AC-50A8-84E9-0127861F8CC0","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('50BECFC6-CD59-5A94-932B-D55FA6ED777E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"50BECFC6-CD59-5A94-932B-D55FA6ED777E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Rocky Pull-Up Pulldown","notes":"","plannedSets":3,"proTips":["Stand in front of a pull-up bar with your feet shoulder-width apart.","Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AF00570D-FD95-5841-8D27-285FF50135D4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('07D22B7B-F99C-5E95-9293-0B13FA64D9BA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Roller","hint":"","id":"07D22B7B-F99C-5E95-9293-0B13FA64D9BA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Hamstrings","Glutes"],"name":"Roller Back Stretch","notes":"","plannedSets":3,"proTips":["Start by sitting on the ground with your legs extended in front of you.","Place the roller perpendicular to your body, just below your glutes.","Slowly roll your body backwards, allowing the roller to move up your back.","Continue rolling until the roller reaches your upper back.","Pause for a moment, then slowly roll back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"4B51CBB3-004A-5126-BA1D-0A9916334CA2","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('6B1F6C97-72B5-5B86-BA46-2AE51973483A'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Roller","hint":"","id":"6B1F6C97-72B5-5B86-BA46-2AE51973483A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps","Core"],"name":"Roller Body Saw","notes":"","plannedSets":3,"proTips":["Start in a plank position with your forearms on the roller and your body in a straight line.","Engage your core and slowly roll the roller forward, extending your body as far as you can while maintaining control.","Pause for a moment at the furthest point, then slowly roll the roller back towards your starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FBB41AB2-C642-5B22-A129-7E4F8F6597A7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('592F6EA3-23D4-5396-AACD-761C298F4D1D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Roller","hint":"","id":"592F6EA3-23D4-5396-AACD-761C298F4D1D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Roller Hip Lat Stretch","notes":"","plannedSets":3,"proTips":["Start by kneeling on the ground with the roller positioned under your hips.","Place your hands on the roller for support.","Slowly roll the roller forward, extending your hips and stretching your glutes.","Hold the stretch for a few seconds, then roll back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"2FD99E6B-09B9-539B-8A07-2C64A616948A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('5506D782-A9F1-561F-A68A-FD14AB8163D2'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Roller","hint":"","id":"5506D782-A9F1-561F-A68A-FD14AB8163D2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Roller Hip Stretch","notes":"","plannedSets":3,"proTips":["Start by sitting on the ground with your legs extended in front of you.","Place the roller under your glutes, just above your knees.","Lean back and place your hands on the ground behind you for support.","Engage your glutes and slowly roll the roller forward, bending your knees and bringing them towards your chest.","Pause for a moment at the end of the movement, feeling a stretch in your glutes.","Slowly roll the roller back to the starting position, extending your legs.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"E41AD83B-30DD-56CD-B98B-220FFACB62F9","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('2A9B3D4A-75BD-5CE0-8023-5F53BDF15102'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Roller","hint":"","id":"2A9B3D4A-75BD-5CE0-8023-5F53BDF15102","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Roller Reverse Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your arms extended straight above your head and your legs straight out in front of you.","Place the roller between your feet and grip it with your toes.","Engaging your abs, lift your legs off the ground and curl your knees towards your chest, rolling the roller towards your body.","Pause for a moment at the top, then slowly lower your legs back down to the starting position, rolling the roller away from your body.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BF21F478-EC9D-5E9D-BDFD-EF013F7EC58A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F7AD9F88-491A-5BF1-AA2D-61EFD82A372A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Roller","hint":"","id":"F7AD9F88-491A-5BF1-AA2D-61EFD82A372A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Roller Seated Shoulder Flexor Depresor Retractor","notes":"","plannedSets":3,"proTips":["Sit on a flat surface with your legs extended in front of you.","Hold the roller with both hands, palms facing down, and place it on your thighs.","Lean forward slightly and roll the roller away from your body, extending your arms straight in front of you.","Pause for a moment, then slowly roll the roller back towards your body, bending your arms and bringing the roller back to your thighs.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4A452289-28E0-55A6-9EF9-7702CA34C4E9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F89CF55E-AABA-52E3-9C46-DBAF4448AE48'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Roller","hint":"","id":"F89CF55E-AABA-52E3-9C46-DBAF4448AE48","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Roller Seated Single Leg Shoulder Flexor Depresor Retractor","notes":"","plannedSets":3,"proTips":["Sit on a flat surface with your legs extended in front of you.","Hold the roller with both hands, palms facing down, and place it on your thighs.","Lean back slightly and engage your core muscles.","Raise the roller up to shoulder level, keeping your arms straight.","Slowly lower the roller back down to your thighs.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"12442DDC-6EC3-5BC1-98F7-D25C0AFBC1E3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9C5A64C2-B9FA-53B4-A837-D354638A186A'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Roller","hint":"","id":"9C5A64C2-B9FA-53B4-A837-D354638A186A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Triceps"],"name":"Roller Side Lat Stretch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the roller with both hands in front of your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms forward and roll the roller down towards your feet, feeling a stretch in your lats.","Hold the stretch for a few seconds, then slowly roll the roller back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"9615A338-F643-5BA4-ABD1-6F613F903605","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('90982F1F-9BF8-5481-ABB8-732E264BCB6A'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Rope","hint":"","id":"90982F1F-9BF8-5481-ABB8-732E264BCB6A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Forearms","Biceps","Shoulders"],"name":"Rope Climb","notes":"","plannedSets":3,"proTips":["Stand facing the rope with your feet shoulder-width apart.","Grab the rope with both hands, palms facing towards you.","Bend your knees slightly and engage your core.","Begin pulling yourself up the rope by alternating hand-over-hand movements.","Use your legs to assist in the upward movement.","Continue climbing until you reach the desired height or the top of the rope.","To descend, reverse the hand-over-hand movement while controlling your descent.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A6D1DE9A-645F-5F96-A69C-29971AD203E1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F0BDE1F8-E034-5908-8844-EBA6EE0AF113'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F0BDE1F8-E034-5908-8844-EBA6EE0AF113","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Run","notes":"","plannedSets":3,"proTips":["Start by standing upright with your feet hip-width apart.","Engage your core and keep your upper body relaxed.","Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.","Maintain a steady pace and continue jogging for the desired duration or distance.","Remember to breathe deeply and maintain good posture throughout the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('888239B2-E963-54C1-B5F9-C55FED290047'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"888239B2-E963-54C1-B5F9-C55FED290047","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Run (Equipment)","notes":"","plannedSets":3,"proTips":["Start by standing upright with your feet hip-width apart.","Engage your core and keep your upper body relaxed.","Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.","Maintain a steady pace and continue jogging for the desired duration or distance.","Remember to breathe deeply and maintain good posture throughout the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('DC2BB2F6-F7B5-55FC-A6DB-F7FBA99E7699'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DC2BB2F6-F7B5-55FC-A6DB-F7FBA99E7699","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Calves","Quadriceps"],"name":"Runners Stretch","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart.","Take a step forward with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down, keeping your left leg straight.","Place your hands on your right thigh for support.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"A47C2781-F883-57E6-802B-1EAB0BC36B71","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('78023303-FF14-595B-9022-F602015BD17F'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"78023303-FF14-595B-9022-F602015BD17F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Russian Twist","notes":"","plannedSets":3,"proTips":["Sit on the ground with your knees bent and feet flat on the floor.","Lean back slightly while keeping your back straight and your core engaged.","Hold your hands together in front of your chest or hold a weight if desired.","Lift your feet off the ground, balancing on your sit bones.","Twist your torso to the right, bringing your hands or weight towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D1430152-1B2F-5634-A347-A96FD28B0803","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F88285E0-FFA2-5A74-B219-81A5CC2D2D15'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F88285E0-FFA2-5A74-B219-81A5CC2D2D15","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Rhomboids","Deltoids"],"name":"Scapula Dips","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and your arms extended in front of you.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your body by bending your elbows and retracting your shoulder blades, as if you are trying to squeeze a pencil between them.","Pause for a moment at the bottom, then push through your hands to extend your elbows and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"30F8EF2F-A727-5857-86D2-7919C78A35A2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D99F4F55-DA7B-5144-88CC-8B6B72312BDA'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D99F4F55-DA7B-5144-88CC-8B6B72312BDA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Serratus Anterior","Triceps","Shoulders"],"name":"Scapula Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your chest towards the ground, keeping your elbows close to your body.","As you lower, squeeze your shoulder blades together and push your chest forward.","Pause for a moment at the bottom, then push back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4A353F6C-5715-5D97-B447-2F555CEBB49E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EFE67880-2BEC-5BDF-9F21-CDDE91A2BD6F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"EFE67880-2BEC-5BDF-9F21-CDDE91A2BD6F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Biceps","Rhomboids","Rear Deltoids"],"name":"Scapular Pull-Up","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.","Retract your shoulder blades by pulling them down and back.","Engage your back muscles and pull your body up towards the bar, focusing on squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C7CA8021-F70B-5B3E-BCB2-594B0AD6D951","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2CDB82DD-D939-5D29-9FA4-836C30B61065'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2CDB82DD-D939-5D29-9FA4-836C30B61065","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Scissor Jumps","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Jump off the ground and simultaneously cross your right leg in front of your left leg.","As you land, quickly switch legs, crossing your left leg in front of your right leg.","Continue alternating legs and jumping as quickly as possible.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('95F87E79-D6D2-5A0F-BD95-1322090E67BE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"95F87E79-D6D2-5A0F-BD95-1322090E67BE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Seated Calf Stretch","notes":"","plannedSets":3,"proTips":["Sit on the edge of a chair or bench with your feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your calf muscle.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"5BC13CE4-DD47-5DE5-8BC4-B5B2E910AC56","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('D0B6098A-699C-56D4-B897-F73B36322A15'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D0B6098A-699C-56D4-B897-F73B36322A15","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings"],"name":"Seated Glute Stretch","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Bend your right knee and cross your right ankle over your left thigh.","Place your right hand on the ground behind you for support.","With your left hand, gently press down on your right knee to deepen the stretch.","Hold the stretch for 30 seconds to 1 minute.","Switch sides and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"3C6F015D-5512-576B-930C-367D9E774DD7","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('1595B98A-6F3F-5E83-8CDF-38EB3705074E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1595B98A-6F3F-5E83-8CDF-38EB3705074E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Seated Leg Raise","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with your back straight and your feet flat on the ground.","Place your hands on the sides of the bench for support.","Keeping your legs straight, slowly raise them up in front of you until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5D653778-4E9C-5924-9F58-041AEE027FCF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C3ED0A15-ED7F-598F-A9A4-C1C9A7C9A303'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C3ED0A15-ED7F-598F-A9A4-C1C9A7C9A303","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Glutes","Hamstrings"],"name":"Seated Lower Back Stretch","notes":"","plannedSets":3,"proTips":["Sit on the edge of a chair with your feet flat on the ground.","Place your hands on your thighs or on the sides of the chair for support.","Slowly lean forward from your hips, keeping your back straight.","Feel the stretch in your lower back and hold for 20-30 seconds.","Slowly return to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"650FA254-BA01-5AA1-98A1-6A3A741C3C07","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('B2D7B8DD-39B7-52D6-8817-7F9B2802DCDF'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B2D7B8DD-39B7-52D6-8817-7F9B2802DCDF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings"],"name":"Seated Piriformis Stretch","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Bend your right knee and place your right foot on the outside of your left knee.","Place your left elbow on the outside of your right knee and gently twist your torso to the right.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"05F25635-7A9E-5570-992C-EAE0097BBB25","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('11DB7AC7-799D-520E-8BE3-57E1CC5B250C'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"11DB7AC7-799D-520E-8BE3-57E1CC5B250C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Seated Side Crunch (Wall)","notes":"","plannedSets":3,"proTips":["Sit on the floor with your back against a wall and your legs extended in front of you.","Bend your knees and place your feet flat on the floor, hip-width apart.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lean to one side, bringing your elbow towards your hip.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F564BDDF-6F78-5026-BF96-4ED7EECE783D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95F1BF58-7B95-55DA-933A-9D8001638DC7'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"95F1BF58-7B95-55DA-933A-9D8001638DC7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Quadriceps","Calves"],"name":"Seated Wide Angle Pose Sequence","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in a wide angle.","Flex your feet and engage your quadriceps.","Place your hands on the ground behind you for support.","Keeping your back straight, lean forward from your hips.","Continue leaning forward until you feel a stretch in your hamstrings.","Hold this position for a few breaths.","Slowly release the stretch and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EB46DC06-B533-5001-BF3F-5A244F691ACC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2B61B119-DF31-5909-A74B-33748CE6FFC7'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2B61B119-DF31-5909-A74B-33748CE6FFC7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Calves"],"name":"Self Assisted Inverse Leg Curl","notes":"","plannedSets":3,"proTips":["Lie flat on your back on a mat or bench with your legs extended.","Place your hands by your sides or under your glutes for support.","Bend your knees and lift your feet off the ground, bringing your thighs towards your chest.","Pause for a moment at the top, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A9360886-BB82-5905-A017-C3BD16DBB3CD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FA3E6816-1E85-501E-A9E0-2F5C5A7C1A38'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"FA3E6816-1E85-501E-A9E0-2F5C5A7C1A38","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Calves"],"name":"Self Assisted Inverse Leg Curl (On Floor)","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and place your feet flat on the ground, hip-width apart.","Lift your hips off the ground, engaging your glutes and hamstrings.","Slowly curl your legs towards your glutes, keeping your hips lifted.","Pause for a moment at the top, then slowly extend your legs back to the starting position.","Lower your hips back down to the ground.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B841798-F344-5CD4-B916-10D22BCF6245","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E88A261A-B128-5D43-8F0B-A9EDB38F65B0'::uuid, '{"category":"Cardio","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"E88A261A-B128-5D43-8F0B-A9EDB38F65B0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Semi Squat Jump","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively, extending your hips and knees while swinging your arms for momentum.","Land softly on the balls of your feet and immediately go into the next repetition.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('AA374F16-8AB5-54AB-BB15-64AEE790879B'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AA374F16-8AB5-54AB-BB15-64AEE790879B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Short Stride Run","notes":"","plannedSets":3,"proTips":["Find an open space or a treadmill to perform the exercise.","Stand tall with your feet hip-width apart.","Start jogging in place, lifting your knees high and pumping your arms.","After a few seconds, start taking short strides forward, maintaining a quick pace.","Continue running with short strides for the desired duration or distance."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('E5C6D201-9BB1-5CE0-A9D7-2CA285AE4E24'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E5C6D201-9BB1-5CE0-A9D7-2CA285AE4E24","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Shoulder Grip Pull-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with a shoulder-width grip, palms facing away from you.","Hang freely with your arms fully extended.","Engage your back muscles and pull your body up towards the bar until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"01CD56E0-2DE3-5435-A76B-023D66D93EB1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('67628628-F33A-5977-93D5-799A803D9873'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"67628628-F33A-5977-93D5-799A803D9873","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps"],"name":"Shoulder Tap","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right hand off the ground, reaching across to tap your left shoulder.","Place your right hand back on the ground and repeat with your left hand tapping your right shoulder.","Continue alternating shoulder taps while keeping your hips and torso stable.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"30432844-C79D-5AAD-9A9C-EACE317D20E4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DA4B5E5F-E67A-58DD-B82A-CF40FD45BEF4'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DA4B5E5F-E67A-58DD-B82A-CF40FD45BEF4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Core"],"name":"Shoulder Tap Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you push back up, lift your right hand off the ground and tap your left shoulder.","Return your right hand to the ground and repeat the push-up, this time lifting your left hand and tapping your right shoulder.","Continue alternating shoulder taps with each push-up repetition.","Maintain a stable core and avoid excessive hip rotation throughout the exercise.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0F908462-F96B-5369-882B-AB3723518DB7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1C75C93D-2078-5D16-B996-9121A8825B08'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1C75C93D-2078-5D16-B996-9121A8825B08","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abductors","Glutes","Obliques"],"name":"Side Bridge Hip Abduction","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs extended and stacked on top of each other.","Prop yourself up on your forearm, keeping your elbow directly below your shoulder.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","While keeping your core engaged, lift your top leg as high as possible without rotating your hips.","Pause for a moment at the top, then lower your leg back down.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"57333361-C7AF-5DF7-A8CA-9BB32A820299","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('920F4F0F-8AE7-5521-AFF0-9382E0670E9D'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"920F4F0F-8AE7-5521-AFF0-9382E0670E9D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Glutes"],"name":"Side Bridge V. 2","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the starting position.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F77AB97E-49AD-5A7B-B1A6-7C8B6C60C897","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFDE231E-C01E-521E-AD44-3724B8B023B9'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AFDE231E-C01E-521E-AD44-3724B8B023B9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Side Hip (On Parallel Bars)","notes":"","plannedSets":3,"proTips":["Stand between two parallel bars with your feet shoulder-width apart.","Place your hands on the bars and lift your body off the ground, supporting your weight on your arms.","Engage your abs and slowly lift your legs to the side, keeping them straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0EA5BF0B-CE19-55EF-8AD5-4C1C293EF32F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('698681F7-DA95-5167-8CAD-8AC601142DA0'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"698681F7-DA95-5167-8CAD-8AC601142DA0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abductors","Glutes","Quadriceps"],"name":"Side Hip Abduction","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your hands on your hips.","Shift your weight to one leg and lift the opposite leg out to the side, keeping it straight.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"01B150C0-F875-516B-A31F-3775A051133A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6AFE8F67-4DDE-5A42-8114-E9A91C876AB6'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6AFE8F67-4DDE-5A42-8114-E9A91C876AB6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Obliques","Glutes"],"name":"Side Lying Floor Stretch","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs straight and your bottom arm extended straight overhead.","Bend your top knee and place your foot on the ground in front of your bottom leg.","Reach your top arm over your head and grab onto something stable, like a wall or a piece of furniture.","Slowly lift your bottom leg off the ground, keeping it straight, until you feel a stretch in your side.","Hold the stretch for 20-30 seconds, then slowly lower your leg back down.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"A5FE06D3-C982-5663-A433-84BA9F5D940B","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('CA4572E8-40F6-5856-8A5F-7B5228AEBB2F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CA4572E8-40F6-5856-8A5F-7B5228AEBB2F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Adductors","Glutes","Hamstrings"],"name":"Side Lying Hip Adduction","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs straight and stacked on top of each other.","Place your bottom arm under your head for support.","Engage your adductors and lift your top leg as high as possible without rotating your hips or leaning backward.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A59DB84D-EED3-5A54-8748-047127AE3A05","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7023EA1B-8799-5E41-8A17-BCD4F279DC48'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7023EA1B-8799-5E41-8A17-BCD4F279DC48","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Adductors","Obliques","Glutes"],"name":"Side Plank Hip Adduction","notes":"","plannedSets":3,"proTips":["Start by lying on your side with your legs extended and stacked on top of each other.","Prop yourself up on your forearm, keeping your elbow directly below your shoulder.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","While maintaining the side plank position, lift your top leg towards the ceiling, keeping it straight.","Slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D3464473-DBF2-5A6F-A775-263FCFF2C742","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A9E96F92-4799-53B6-9E5E-411366DF78F4'::uuid, '{"category":"Neck","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A9E96F92-4799-53B6-9E5E-411366DF78F4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Levator Scapulae","Trapezius","Sternocleidomastoid"],"name":"Side Push Neck Stretch","notes":"","plannedSets":3,"proTips":["Stand or sit up straight with your shoulders relaxed.","Tilt your head to the right, bringing your right ear towards your right shoulder.","Place your right hand on the left side of your head and gently apply pressure to increase the stretch.","Hold the stretch for 15-30 seconds.","Repeat on the other side, tilting your head to the left and applying pressure with your left hand.","Repeat the stretch 2-3 times on each side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"5763B24B-AA5A-5FA4-B284-64F3CA80CDAC","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('A48821F1-3CD0-560D-9C08-C68DA54611E0'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A48821F1-3CD0-560D-9C08-C68DA54611E0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Chest","Core"],"name":"Side Push-Up","notes":"","plannedSets":3,"proTips":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your bottom hand on the ground directly under your shoulder, fingers pointing forward.","Press through your bottom hand to lift your body off the ground, keeping your legs straight and your core engaged.","Extend your top arm straight up towards the ceiling, creating a straight line from your head to your heels.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"78C368DA-078B-5B22-A58B-45BDA1992E34","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('73F0934E-95C4-51B3-8536-4F582673C0C7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"73F0934E-95C4-51B3-8536-4F582673C0C7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Wrists","Hands"],"name":"Side Wrist Pull Stretch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms extended in front of you.","Extend your right arm out to the side, parallel to the ground, with your palm facing down.","With your left hand, grab your right hand and gently pull it towards your body, feeling a stretch in your right forearm.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"53ED34BA-034E-55A8-B292-862FEC19D3F9","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('6F128C33-9FA7-5FEA-B183-22FCED6E4F21'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6F128C33-9FA7-5FEA-B183-22FCED6E4F21","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Side-To-Side Chin","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body relaxed.","Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight.","Once your chin is above the bar, lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F4F3090B-419B-5C64-8766-955BC3E41D1C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('861BC100-7D4E-5B30-A326-3A5943763B8B'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"861BC100-7D4E-5B30-A326-3A5943763B8B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Side-To-Side Toe Touch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms extended to the sides.","Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side.","Return to the starting position and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side.","Repeat the side-to-side bending motion for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"746D2C86-9DA3-5197-A5A1-363CB9E84B22","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FC1DEC2E-466F-5622-A839-F506003FE574'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"FC1DEC2E-466F-5622-A839-F506003FE574","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Single Arm Push-Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and one hand placed slightly wider than the other.","Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.","As you lower yourself, shift your weight to one side and lift the opposite arm off the ground, extending it straight out to the side.","Push through your chest and triceps to raise your body back up to the starting position, while simultaneously lowering your extended arm back to the ground.","Repeat the movement, alternating the arm you extend with each repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CD69AE5B-A485-5F29-90CD-B097DFAA6BAD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('954073BF-9BCE-5FE8-82B5-1C3B8BC66B34'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"954073BF-9BCE-5FE8-82B5-1C3B8BC66B34","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Single Leg Bridge With Outstretched Leg","notes":"","plannedSets":3,"proTips":["Lie on your back with your knees bent and feet flat on the ground.","Extend one leg straight out in front of you.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","Hold for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"EA8C90B1-28F0-58CE-AD4E-43B863FE52D3","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('7349F7F7-77B4-5791-ADEA-451232922E83'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7349F7F7-77B4-5791-ADEA-451232922E83","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Single Leg Calf Raise (On A Dumbbell)","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and hold a dumbbell in one hand.","Lift one foot off the ground and balance on the other foot.","Slowly raise your heel as high as possible, using your calf muscles.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch to the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8DFDCB2E-5286-51D8-BAD1-1FF6E008B8C6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8BD522EB-BEF4-52D4-B05C-D1D639A3EA7C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8BD522EB-BEF4-52D4-B05C-D1D639A3EA7C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Quadriceps"],"name":"Single Leg Platform Slide","notes":"","plannedSets":3,"proTips":["Start by standing with one foot on a platform or slide board.","Bend your knee slightly and slide the foot on the platform backward, extending your leg.","Keep your core engaged and maintain a straight posture throughout the movement.","Slowly return to the starting position by sliding your foot back to the initial position.","Repeat the movement for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"424CB036-380A-5C35-9F4C-3540B4569919","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('88708E44-B6C0-57B7-996E-EB28C263201A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"88708E44-B6C0-57B7-996E-EB28C263201A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Single Leg Squat (Pistol) Male","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and arms extended in front of you.","Lift your right foot off the ground and extend it forward.","Slowly lower your body down by bending your left knee and pushing your hips back.","Keep your chest up and your back straight as you lower yourself down.","Lower until your left thigh is parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your left heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"45F7D8AC-FB15-5B88-A849-68978DB2FD94","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AA514DBF-E2EC-53F0-999F-071F357E5C6A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"AA514DBF-E2EC-53F0-999F-071F357E5C6A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Calves","Glutes"],"name":"Sissy Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your toes pointing slightly outward.","Hold onto a stable object for balance if needed.","Slowly lower your body by bending your knees and leaning back, keeping your torso upright.","Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6B424369-E201-51BA-B5E8-B003B9798B55","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('447BD0E5-680D-5A34-BE0A-22DA109FB5B3'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"447BD0E5-680D-5A34-BE0A-22DA109FB5B3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Sit-Up V. 2","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A1D80B98-FD53-591B-8096-1E08BFD93291","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A03A5E54-47B1-5C43-B575-7ACB258163F6'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A03A5E54-47B1-5C43-B575-7ACB258163F6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Sit-Up With Arms On Chest","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Cross your arms over your chest.","Engaging your abs, lift your upper body off the ground towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"83D19547-D7E3-594C-B9CF-97DEB062E035","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C1D9B1D3-A4DF-5B7C-8664-FB27A91F894C'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C1D9B1D3-A4DF-5B7C-8664-FB27A91F894C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"Skater Hops","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump to the right, landing on your right foot.","As you land, swing your left leg behind your right leg and tap the ground with your left toes.","Immediately jump to the left, landing on your left foot.","As you land, swing your right leg behind your left leg and tap the ground with your right toes.","Continue alternating sides, jumping and tapping the ground with each leg.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('3D2154C8-BA41-589C-A561-7B13613563F1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cardio Machine","hint":"","id":"3D2154C8-BA41-589C-A561-7B13613563F1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Forearms"],"name":"Ski Ergometer","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footrests to a comfortable position.","Grasp the handles with an overhand grip, palms facing down.","Sit up straight with your feet flat on the footrests.","Extend your arms straight out in front of you, keeping your elbows slightly bent.","Engage your triceps and push the handles down towards your thighs.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('A168D592-414A-58E4-8421-F5FCBD769C75'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A168D592-414A-58E4-8421-F5FCBD769C75","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"Ski Step","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees slightly and keep your back straight.","Jump to the right, landing on your right foot while swinging your left leg behind your right leg.","Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg.","Continue alternating jumps from side to side, mimicking a skiing motion.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('293F3C77-F92C-557E-82D4-4A2926D0073A'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"293F3C77-F92C-557E-82D4-4A2926D0073A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Core"],"name":"Skin The Cat","notes":"","plannedSets":3,"proTips":["Start by hanging from a bar with your arms fully extended and your body relaxed.","Engage your core and lift your legs up, bringing your knees towards your chest.","Continue to lift your legs up and over your head, allowing your body to pass through the arms.","Once your legs are fully extended over your head, begin to lower them back down towards the starting position.","As you lower your legs, allow your body to pass back through the arms until you are hanging with your arms fully extended again.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"982C9D40-8C8E-548A-AD66-3117E912BF7A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3724778F-592E-58DE-9CA5-8182BBFF7785'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"3724778F-592E-58DE-9CA5-8182BBFF7785","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled 45 Degrees One Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a 45-degree angle.","Sit on the sled machine with your back against the pad and your feet on the footplate.","Place one foot on the footplate and extend your leg, pushing the sled away from you.","Slowly bend your knee and lower the sled back to the starting position.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0F906ABA-8C63-5C2D-B774-2F6F40DCA6A4","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"353EBEEC-D4C7-5750-8070-3584EF9337C6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3E446B69-1165-59ED-A157-16EA895BB107'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"3E446B69-1165-59ED-A157-16EA895BB107","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled 45° Leg Press (Side POV)","notes":"","plannedSets":3,"proTips":["Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate.","Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate.","Grip the handles on the sides of the seat for stability.","Push against the footplate to extend your legs, straightening them completely.","Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2E00517F-61DC-5B3C-AC5C-721C653EFC23","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"08E2A4FF-EA3E-509C-8D55-EDBA7BDEA7D5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AC4BBE3D-607D-5127-B94D-C3DC9691A3E0'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"AC4BBE3D-607D-5127-B94D-C3DC9691A3E0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Sled 45в° Calf Press","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a 45-degree angle.","Place your feet on the sled platform with your toes pointing forward.","Push the sled platform away from you by extending your ankles and calves.","Pause for a moment at the top, then slowly lower the sled platform back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E2BC60D3-D5AE-5ED5-8A83-B5A7AF57FB03","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"560F1663-9428-54F4-AD9A-07406B85EB08","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7594516A-26B9-55A5-8D97-248BA7FC158D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"7594516A-26B9-55A5-8D97-248BA7FC158D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled 45в° Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the seat and footplate of the sled machine to a comfortable position.","Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Grip the handles on the sides of the seat for stability.","Push the footplate away from your body by extending your legs, keeping your heels on the footplate.","Continue pushing until your legs are almost fully extended, but without locking your knees.","Pause for a moment at the top of the movement, then slowly lower the footplate back towards your body by bending your knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B06ECFE6-A87B-5F14-BBEB-F1387E78B470","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"8C3E95B4-7842-5EE3-B1B8-97214650F486","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6FEC615E-840E-5875-8BE0-F498488B0631'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"6FEC615E-840E-5875-8BE0-F498488B0631","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled 45в° Leg Press (Back POV)","notes":"","plannedSets":3,"proTips":["Adjust the seat of the sled machine so that your knees are at a 45-degree angle.","Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Grip the handles on the sides of the seat for stability.","Push the footplate away from your body by extending your legs, keeping your heels on the footplate.","Pause for a moment at the fully extended position.","Slowly bend your knees and lower the footplate back towards your body, controlling the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1D65182C-4C1B-5213-B61D-80E8196C2D66","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A24692BA-EEE6-51E8-B4CB-F9E7610EFCC9","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('249757C7-9618-5CA7-B12C-19D1D46FA808'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"249757C7-9618-5CA7-B12C-19D1D46FA808","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled 45в° Leg Wide Press","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a 45-degree angle.","Sit on the sled machine with your back against the pad and your feet on the foot platform.","Position your feet wider than shoulder-width apart.","Push against the foot platform to extend your legs and straighten your knees.","Pause for a moment at the end of the movement, then slowly bend your knees to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"14D80894-6CDC-579F-89A4-434ECF117E02","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"55AB6604-8DBC-502D-9299-4CDE032CFB86","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C6984A6A-D067-52B3-82ED-EC7E9578696B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"C6984A6A-D067-52B3-82ED-EC7E9578696B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Sled Calf Press On Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled.","Place your feet shoulder-width apart on the sled, with your toes pointing forward.","Release the safety handles and push the sled away from you by extending your knees and ankles.","Pause for a moment at the top of the movement, then slowly lower the sled back down by bending your knees and ankles.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E729EFED-5E66-5825-A4EF-57F35B247EC5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D0DE70A7-03A3-5237-8A4B-9F7A32C4E2C1","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EF1CC59E-653F-5B22-AB8B-9B8A24415410'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Machine","hint":"","id":"EF1CC59E-653F-5B22-AB8B-9B8A24415410","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled Closer Hack Squat","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a comfortable weight and position yourself with your back against the pad.","Place your feet shoulder-width apart on the platform, toes slightly pointed outwards.","Grip the handles on the sides of the machine for stability.","Engage your core and slowly lower your body by bending your knees and hips, keeping your back straight.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment at the bottom, then push through your heels to extend your legs and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BD47418D-D2BC-5D89-91D2-5ED0999369BC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"70BE39FF-1356-5107-BA25-97B49975180B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('36AECE81-C8E4-5A15-8653-68F5B61DA3CE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"36AECE81-C8E4-5A15-8653-68F5B61DA3CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Sled Forward Angled Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a comfortable weight and position yourself on the machine with your toes on the platform and your heels hanging off.","Place your hands on the handles or the sides of the machine for support.","Engage your calves and slowly raise your heels as high as possible, pushing against the resistance of the sled.","Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DDC082F9-11EA-5280-9A78-E9668A1EA642","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7AFB7671-67EC-51A5-B1DE-DB9D8EB1DD2F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('84E954D5-A1A8-5AE4-9C9E-98B58C729819'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Machine","hint":"","id":"84E954D5-A1A8-5AE4-9C9E-98B58C729819","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled Hack Squat","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a comfortable position for your height.","Stand with your feet shoulder-width apart on the platform, toes slightly pointed outwards.","Hold onto the handles or bars for stability.","Lower your body by bending your knees and hips, keeping your back straight and chest up.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"09D4AEDF-366E-5288-8733-4790078611D5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D8919845-56DE-5250-9D4C-9C577C3F5CC8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4B457A7B-3889-5343-BDE7-F6FAFB359C69'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"4B457A7B-3889-5343-BDE7-F6FAFB359C69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Sled Lying Calf Press","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a comfortable weight.","Sit on the sled machine with your back against the pad and your feet on the platform.","Place your toes and the balls of your feet on the edge of the platform, with your heels hanging off.","Push the platform away from you by extending your ankles, keeping your knees slightly bent.","Continue pushing until your calves are fully contracted.","Hold the contraction for a moment, then slowly lower the platform back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4054C48B-40EC-5B76-8E3C-4CAD8C9CF9C1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"2874FBD9-5B34-594F-9BF6-154E379A431F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B17F382-4657-54D8-91BF-B017715FC799'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Machine","hint":"","id":"0B17F382-4657-54D8-91BF-B017715FC799","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Sled Lying Squat","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a comfortable weight.","Lie on your back on the sled machine with your feet on the footplate.","Position your feet shoulder-width apart and slightly angled outwards.","Grip the handles of the sled machine for stability.","Engage your glutes and core muscles.","Push through your heels and extend your legs to lift the sled.","Lower the sled back down by bending your knees and hips.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"ABB52CBA-C3A9-5662-9555-212E49D653F9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"70860AA0-E849-551E-AC8C-8DF3FE4BD839","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8769C2DD-AE93-5B86-B416-28966BAC1CD2'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"8769C2DD-AE93-5B86-B416-28966BAC1CD2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Sled One Leg Calf Press On Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled.","Sit on the machine with your back against the backrest and your feet on the sled, shoulder-width apart.","Place your toes and the balls of your feet on the sled, keeping your heels off.","Push the sled forward by extending your ankles, keeping your knees slightly bent.","Pause for a moment at the top, then slowly lower the sled back down by flexing your ankles.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A25D9951-D43A-51C6-9553-DBA2F7D48FEA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0DB9750D-082B-5FCA-B58D-1FAE43E2CED2","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('64583732-8963-5FBE-B7EE-EB3F350C5EF2'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Machine","hint":"","id":"64583732-8963-5FBE-B7EE-EB3F350C5EF2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Forearms","Shoulders"],"name":"Sledge Hammer","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the sledge hammer with both hands.","Engage your core and keep your back straight.","Swing the sledge hammer down towards the ground, using your core and upper body strength.","As you swing down, pivot your hips and transfer the force to the hammer.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0FDB5F79-C7B2-5393-BC10-9E9873D388F1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"45FFE292-B289-517B-8DC4-AEFC2374DBE5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('033775EC-99BD-53F5-B036-596E64D2F0A5'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"033775EC-99BD-53F5-B036-596E64D2F0A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Smith Back Shrug","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your arms straight and allow the barbell to hang in front of your thighs.","Lift your shoulders straight up towards your ears, squeezing your traps at the top.","Hold for a moment, then lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A7CD00D5-AD6F-5C7F-B155-EFDC2AEC20E1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"13E38DF6-A638-5E7F-A06A-E7A44E48EFC6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7B839D81-69FC-50FB-93DD-4D0F96A29793","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F9BF1E9B-184C-5F1C-B2E7-D6E74FE442D5","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4DB5D68D-1404-539C-9EE9-E1F0A009A5BA'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"4DB5D68D-1404-539C-9EE9-E1F0A009A5BA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Smith Behind Neck Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height of the smith machine so that the bar is at shoulder level.","Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lift the bar off the rack and step back, maintaining a stable stance.","Lower the bar down to the back of your neck, keeping your elbows pointing forward.","Press the bar up overhead until your arms are fully extended.","Pause for a moment at the top, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"FD4B6722-337D-5315-BD24-A10FDED9A5DA","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"25373229-D32B-5AA3-9171-FABE3CB8F211","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"893D068B-8B5B-5023-8959-C9F97963BBFD","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"959A7B87-F0B5-5757-8059-8A8FCC4F5046","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7FF30E7C-748B-58F8-8633-76CD6176DBC6'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"7FF30E7C-748B-58F8-8633-76CD6176DBC6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the height of the smith machine bar to chest level.","Lie flat on the bench with your feet firmly planted on the ground.","Grip the bar with an overhand grip slightly wider than shoulder-width apart.","Unrack the bar and lower it towards your chest, keeping your elbows tucked in.","Pause for a moment when the bar touches your chest.","Push the bar back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E31183A8-73A7-53D5-AFD5-47619AF83585","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"635D8110-2E2A-5F2A-8EC7-FE20B2A1E9CE","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3A55E520-5F89-55E0-B95E-D310AB590F74","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F1AE0C1B-E32A-598E-B6AF-24B2331E4CD2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('672F0B39-AB79-5985-9703-D0E0BFECC708'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"672F0B39-AB79-5985-9703-D0E0BFECC708","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Smith Bent Knee Good Morning","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, toes pointing forward.","Place the barbell across your upper back, resting it on your traps.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Engage your glutes and hamstrings to raise your torso back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"505C70B2-8D80-5619-AA71-ADDFAC911C4C","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"BE9A2A83-B906-55EC-A54C-5BE4CA0161F2","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A3B5552E-47F4-5DA4-8332-0E719875CB13","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"27C164E3-BD39-52DE-8C2A-55691688D967","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F3FFA0BE-09BB-5192-BE75-FB650E7B7651'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"F3FFA0BE-09BB-5192-BE75-FB650E7B7651","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Smith Bent Over Row","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the bar at hip height.","Stand facing the bar with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Pull the bar towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7D227E5E-D352-5C85-ABE1-CDD21246A4F0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"7ECA611D-13EA-5372-B7D9-AF6876BDE7B3","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CCF41461-5C96-52E7-8E4E-F49EFA16D885","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2D536588-370C-5A5C-874C-10427E3EF0B8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AC2B8F0C-9F2B-5726-AE8C-A6F0CBFCFF4A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"AC2B8F0C-9F2B-5726-AE8C-A6F0CBFCFF4A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Smith Chair Squat","notes":"","plannedSets":3,"proTips":["Adjust the height of the smith machine bar to a comfortable position.","Stand with your feet shoulder-width apart, toes slightly turned out.","Place the barbell across your upper back, resting it on your traps.","Engage your core and keep your chest up as you slowly lower your body by bending your knees and hips.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1A26E74B-8A60-5F93-84FD-5FFACEBC2566","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F60D886C-F97D-5658-A94C-D6604014BD21","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EEED937D-A95B-57B0-A3F7-6EEC71532D4E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"619FD95C-88DA-5D55-AA3D-32A480FDE6F8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('24EBDF17-7A20-55A9-B34C-A2D95454ABC1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"24EBDF17-7A20-55A9-B34C-A2D95454ABC1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Smith Close-Grip Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the bench with your feet flat on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"6FE4EBEC-E34A-537D-9A59-2FEE45D8BD24","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F2D3B541-8C57-5C84-A189-1FA450E8E337","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B1815405-BDB7-5C17-977B-AEB18BA8F272","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"890C48E6-8DD7-5EF4-BE6C-A96544F6212D","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5138A304-3915-5FBC-9F90-76AB4E95C284'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"5138A304-3915-5FBC-9F90-76AB4E95C284","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Lower Back"],"name":"Smith Deadlift","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the bar at hip height.","Stand with your feet shoulder-width apart, toes pointing slightly outward.","Bend at the hips and knees, keeping your back straight and chest up, and grip the bar with an overhand grip slightly wider than shoulder-width apart.","Engage your core and lift the bar by extending your hips and knees, keeping the bar close to your body.","Stand up straight, fully extending your hips and knees.","Lower the bar back down by bending at the hips and knees, maintaining control and keeping your back straight.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A9D1CA6F-54D7-517A-80BB-9E9D34BD5457","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"370D7BB9-CAFD-5C63-B20F-97FE38FAE86F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EBD92C1A-4620-525A-AC7D-1A108B6635F1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3BA76576-B346-55C4-9B8A-094E2CA2B2D9","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('54D93F67-75AA-592B-A4A3-FB44BBBBDB67'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"54D93F67-75AA-592B-A4A3-FB44BBBBDB67","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Decline Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the decline bench to the desired angle.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4352F95A-50EA-578D-A3CA-DB1271AE8CFF","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"17C45D9B-5B89-5997-967B-B1D16AF4165F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"943647DE-B01B-505D-816C-91D496FE7EF0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F02760EF-02E8-5636-9558-B35AE0C60753","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B6AE1749-C485-5559-8EC4-E936A99AC583'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"B6AE1749-C485-5559-8EC4-E936A99AC583","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Decline Reverse-Grip Press","notes":"","plannedSets":3,"proTips":["Adjust the smith machine to a decline position.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A6258BAC-A411-5814-B089-3FDF0A53CCFC","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"27833A5B-3800-5FEF-858A-AA900F167759","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CC9384AF-25E9-5A26-BAF3-CD257AD820A7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"5F0745E0-AF24-58EA-95D3-B3BC62405F9E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EA5EC7FE-7528-508F-B43C-F7C2EA691A61'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"EA5EC7FE-7528-508F-B43C-F7C2EA691A61","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Smith Front Squat (Clean Grip)","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the barbell at shoulder height.","Stand facing the barbell with your feet shoulder-width apart.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Step back and position the barbell on your front shoulders, resting it on your collarbone and deltoids.","Keep your chest up, back straight, and core engaged.","Lower your body by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"5728F9B5-5FCE-5479-9C15-DFBB0631E180","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0B29F99E-316A-5BE5-A984-971681EA3DF8","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"D29CE704-1DB9-5741-9DFA-FA6D9296A603","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"315FEB01-2CD5-5E0B-B092-7CE479132D9B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('60C0752C-2C7B-5D9A-BC9D-34D796B33BA2'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"60C0752C-2C7B-5D9A-BC9D-34D796B33BA2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Full Squat","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the barbell at shoulder height.","Stand with your feet shoulder-width apart, toes slightly turned out.","Step under the bar and position it across your upper back, resting on your traps.","Grip the bar with your hands slightly wider than shoulder-width apart.","Unrack the bar and take a step back, maintaining a stable stance.","Keeping your chest up and core engaged, initiate the squat by pushing your hips back and bending your knees.","Lower your body until your thighs are parallel to the ground, or as low as your flexibility allows.","Pause for a moment at the bottom, then drive through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"61AA27CA-B8B4-5E6B-ADB6-A7DD4309BCBE","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"AE19E2CB-C4E3-5367-A31E-609DE88FB5F9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7ABF2648-1EB0-5EED-AC5C-A89EE27DE5BD","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9D8AE3CA-FB87-5C6D-A10A-CFFEB9DE03C0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('64F62379-75A7-58B4-B46A-8C3E3F0C0658'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"64F62379-75A7-58B4-B46A-8C3E3F0C0658","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Hack Squat","notes":"","plannedSets":3,"proTips":["Adjust the barbell on the smith machine to an appropriate height for your body.","Stand with your feet shoulder-width apart, toes slightly pointed outwards.","Position yourself under the barbell, resting it on your upper traps and shoulders.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and keep your chest up as you unrack the barbell.","Take a step back and position your feet slightly wider than shoulder-width apart.","Bend your knees and lower your body down, keeping your chest up and back straight.","Continue descending until your thighs are parallel to the ground or slightly below.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"469AD964-DE35-5D43-A6C3-01DBE7F65E9E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"293E4B46-EC5A-5644-B12B-574B1AB27301","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7A320B76-BE77-5085-9E3A-841523D5CC7D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E9435869-0D2B-5A47-9793-FD81EC92F321","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95CD12CF-6614-5124-9400-642648564BB4'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"95CD12CF-6614-5124-9400-642648564BB4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Glutes","Hamstrings"],"name":"Smith Hip Raise","notes":"","plannedSets":3,"proTips":["Position yourself on the smith machine with your back against the pad and your feet shoulder-width apart.","Place your hands on the barbell, slightly wider than shoulder-width apart.","Engage your core and glutes, then push through your heels to raise your hips off the ground.","Continue lifting until your body forms a straight line from your knees to your shoulders.","Hold for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"18FF2579-751C-5E2E-B7D5-C3144005534F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"94C0B35F-2520-5A36-8A68-5E84BFAE0F16","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9643D27E-F343-5496-A0C4-3C407CA737F8","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9CEA922C-E9F3-51DC-847D-02A3CA2C34E6","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B8B4ADBC-2CD0-5C42-9928-560727EE6D5E'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"B8B4ADBC-2CD0-5C42-9928-560727EE6D5E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Smith Incline Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the bench to a 30-45 degree incline.","Sit on the bench with your back flat against the pad and feet firmly on the ground.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"170F5720-A81F-5CFD-B02F-0D78181B6050","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1966986E-321B-505C-BAF5-F26B65C2C78B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"D712F910-046E-5066-8505-B0EA789270E0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D515E874-C176-574D-AF73-21DEC4215E56","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('489A9CC7-EC53-54FD-8046-AA3322E8AB8F'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"489A9CC7-EC53-54FD-8046-AA3322E8AB8F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Incline Reverse-Grip Press","notes":"","plannedSets":3,"proTips":["Adjust the seat of the smith machine to a comfortable incline angle.","Sit on the machine with your back against the pad and your feet flat on the ground.","Grasp the bar with an overhand grip that is slightly wider than shoulder-width apart.","Unrack the bar and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the bar is just above your chest.","Push the bar back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"13A4151F-A864-5BB3-921B-B3BCCCC343FF","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A3E31905-14F0-54A1-91F9-61491951F058","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"96E2755D-A568-5769-82A2-37B7D3EC8DAB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4EDBFE22-3AB1-5AD3-B95D-FB9B8759CB4E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DF9C08B8-3F1A-5A7A-B86C-EF2298A83275'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"DF9C08B8-3F1A-5A7A-B86C-EF2298A83275","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Serratus Anterior","Deltoids","Trapezius"],"name":"Smith Incline Shoulder Raises","notes":"","plannedSets":3,"proTips":["Adjust the smith machine to an incline position.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and core engaged.","Raise the barbell up towards the ceiling, leading with your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AA7E4EE7-FF1E-535A-9C16-3F2652312D2B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"76A22100-4148-5C36-BF9E-B7359B164914","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"66AA4B54-7391-5494-B8B8-4451ACC474D2","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"5826AA4F-C76E-5DA1-A3DD-E1B9F7BAC9BF","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6FD979AE-AFE7-557F-9192-DF86571BD39F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"6FD979AE-AFE7-557F-9192-DF86571BD39F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the seat and footplate of the smith machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Grasp the handles or sides of the machine for stability.","Push the footplate away from you by extending your legs, keeping your back against the backrest.","Pause for a moment at the fully extended position.","Slowly bend your knees and lower the footplate back towards you, returning to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E3482F4F-DF9D-57C9-9523-3700C2548FB7","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8707CC3C-907D-5EED-AF67-E2E99DB6777F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"00611455-61FA-5DE4-B7D8-F890305EAAE1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D1C631CE-7E37-51CC-84A1-13650AE0BDD3","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F5541EB7-AA10-5C28-92E8-E70010D823B3'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"F5541EB7-AA10-5C28-92E8-E70010D823B3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Low Bar Squat","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the barbell at a height that allows you to comfortably rest it on your upper back.","Stand with your feet shoulder-width apart, toes slightly turned outwards.","Step under the bar and position it across your upper back, resting it on your traps.","Grip the bar with your hands slightly wider than shoulder-width apart.","Unrack the bar by straightening your legs and stepping back from the rack.","Take a deep breath and brace your core.","Initiate the squat by pushing your hips back and bending your knees.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your chest up and your back straight throughout the movement.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E8F63C13-686D-57D8-9913-C131390CC42F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"4EA3AC62-797C-55A5-9C45-FD2C79029B28","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EFB8D815-3A4D-5B74-A0C4-2D245C70B7A7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"61AC0451-5B0E-5EDA-831E-C87EBE134EE1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D047D73A-84DE-5820-A4D9-154A3860C24D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"D047D73A-84DE-5820-A4D9-154A3860C24D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Smith Machine Bicep Curl","notes":"","plannedSets":3,"proTips":["Adjust the height of the smith machine bar to be at waist level.","Stand facing the smith machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands slightly wider than shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"B8BC4556-DA78-5C39-9E9A-DB5760398F3D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2A69275A-55CD-5AE0-AC4F-37AB7589B68D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9363E413-C3AB-5DEB-8342-AE282720D15E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9B01F6B2-839C-56EA-BF39-0146D67E8363","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B428B0D-1EC2-50D7-8A14-C0FF537EAA43'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"0B428B0D-1EC2-50D7-8A14-C0FF537EAA43","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Smith Machine Decline Close Grip Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the bench on the smith machine to a decline position.","Lie down on the bench with your feet firmly planted on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell is just above your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"35DF24EF-51CB-5D47-A170-4E3FCB3EBC98","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A4EC4BCA-48DB-5ECF-926C-A81153030D77","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5EC2C1ED-7D70-5D07-9784-2ABCFB5F625F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2C89A96E-ED24-5211-9365-29DF3B0CA8AF","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('596361DA-7463-5C3F-96E8-C68CFA686BE2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"596361DA-7463-5C3F-96E8-C68CFA686BE2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Smith Machine Incline Tricep Extension","notes":"","plannedSets":3,"proTips":["Adjust the seat of the smith machine so that the bar is at shoulder height.","Sit on the bench with your back against the pad and your feet flat on the ground.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Extend your arms fully, lifting the bar off the rack and holding it directly above your chest.","Lower the bar slowly towards your forehead, keeping your elbows close to your head.","Pause for a moment at the bottom, then push the bar back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"EEF7BDF6-5CD8-59F1-8D83-82E16193B8F7","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"791DC497-085F-51D9-A941-B06BA3A4F8B4","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"298F7BCF-2887-5A45-89B1-1F011BC0DB21","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"85DA9AE4-3302-5A52-923E-78E62B434273","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('727FA0D5-AF02-5513-B629-B73D34E0B5F2'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"727FA0D5-AF02-5513-B629-B73D34E0B5F2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Machine Reverse Decline Close Grip Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the smith machine to a decline position.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"786B42FC-F0E1-5916-AEB9-092684EAF5BD","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"4EDAD2CC-A042-5733-B15F-841773F636A8","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CF82B799-0655-5450-A3E0-A88AD4082766","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4394262F-110B-52D6-9E56-49EBC57E067C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('042F66A2-1DAF-5C4C-AB26-FFBAEE43E8E6'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"042F66A2-1DAF-5C4C-AB26-FFBAEE43E8E6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Rear Deltoids"],"name":"Smith Narrow Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your feet flat on the floor.","Grasp the handles with an overhand grip, slightly narrower than shoulder-width apart.","Keep your back straight and your chest up as you pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7C5E42DF-4480-57D2-B9B6-437C3FA91B97","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"86448058-B1EB-5015-8A87-384582B3B0D0","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0C0887E8-2698-58E0-8F3E-A670FBE05808","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"71C45FCC-9F97-5662-B151-84F037F019A0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('640687C1-2E9B-554E-85C0-10D78B41D304'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"640687C1-2E9B-554E-85C0-10D78B41D304","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Smith One Arm Row","notes":"","plannedSets":3,"proTips":["Adjust the height of the smith machine bar to waist level.","Stand facing the smith machine with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the bar with one hand using an overhand grip, with your palm facing down.","Keep your elbow close to your body and pull the bar towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly lower the bar back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"EE19F624-A86A-5AB0-9F45-757D3EA660C1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"273F4A44-1F85-5C1E-81FF-A73915574DC8","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9F8D1CDE-FC5E-5D0F-9BC4-27E22A7F118E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"FB9B9BB0-C280-5746-A6D3-3AD0C99CFF9A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C7F80D50-A519-56BD-A483-1758D7025A28'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"C7F80D50-A519-56BD-A483-1758D7025A28","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Smith One Leg Floor Calf Raise","notes":"","plannedSets":3,"proTips":["Position yourself on the floor under the smith machine bar, facing away from the machine.","Place the balls of your feet on a raised surface, such as a weight plate or block.","Position the smith machine bar across your lower legs, just above your ankles.","Hold onto the bar with your hands for stability.","Raise your heels off the ground by extending your ankles, lifting your body up.","Pause at the top of the movement, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"C3F7CFF1-21E8-50D4-BCBF-1636D58A8C5E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"98CB4E0B-5E34-542B-A540-233968C5EA5D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A8277783-E213-5B18-B712-F28CB7DC6D03","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B98C8DCF-F0F7-5F23-8C98-1C02631503D1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('21764869-FC3C-5585-8C42-4542A569126B'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"21764869-FC3C-5585-8C42-4542A569126B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Smith Rear Delt Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and your core engaged as you pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E97C6F12-1639-519A-9F70-2477B06D7A9B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"7A051EA4-4AFD-556C-9D64-B88516E15704","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"50778D52-71E2-5CBD-9A65-141F7FE5E7DF","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D356D0ED-138E-5934-B781-FB46EB852414","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6441D408-067A-51BA-AB1D-E8985D4CB64B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"6441D408-067A-51BA-AB1D-E8985D4CB64B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Smith Reverse Calf Raises","notes":"","plannedSets":3,"proTips":["Adjust the smith machine bar to a height just below your shoulders.","Stand facing the bar with your feet hip-width apart and toes pointing forward.","Place the balls of your feet on the edge of a step or platform, with your heels hanging off.","Hold onto the bar for support, keeping your back straight and core engaged.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AB42180F-236B-5ED9-8538-282086CDFF16","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"01A685C0-0FE8-54F9-B6C6-06CC49D37416","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"30E2CCCB-6710-583A-8B60-8ECE152CDE5C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"A6A38BD3-488B-5A80-A63C-EEA914EFE023","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EF2D6AA1-42AD-5A21-92C9-148BDC422DB1'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"EF2D6AA1-42AD-5A21-92C9-148BDC422DB1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Smith Reverse Grip Bent Over Row","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the bar at hip height.","Stand facing the bar with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Pull the bar towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1AB196A1-2C27-5B58-B1A4-81BE3FDA8D62","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5CE3566C-9233-5CC2-B551-AD13C9736408","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E101B378-C438-55CA-BAC4-E8AF3778254D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"5E542F2E-4CC2-5A6D-883E-AC0CD37D5AF5","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('15FD20EB-0C47-56FE-B0A7-9C4834B6F99B'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"15FD20EB-0C47-56FE-B0A7-9C4834B6F99B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Reverse-Grip Press","notes":"","plannedSets":3,"proTips":["Adjust the height of the smith machine bar to chest level.","Stand facing the bar with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Step back and position yourself with a slight bend in your knees.","Keep your chest up and core engaged throughout the exercise.","Lower the bar towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the bar back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"53459F55-16A7-59F6-861B-D6B1F87FCDF6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B85063A3-2A88-5EC4-A6A9-60346E95A901","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4D5DB56D-3EEB-5D23-8C10-C5E810F6C75C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"350CB56C-2CFE-5B1E-A32E-501FF78CD69A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7AE30DF9-4380-5A7C-A24D-8D29C9116255'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"7AE30DF9-4380-5A7C-A24D-8D29C9116255","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Smith Seated One Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Sit on the machine with your back against the pad and your feet on the footrest.","Place one leg on the footrest and keep the other leg off the footrest.","Using your calf muscles, raise your heel as high as possible.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7F63993B-304C-5155-8B9C-3FE1F3AC8EC3","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B0E29820-ABA4-5B84-A58E-E3FD5291EE3C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"2CF04C76-3BD3-5810-89FB-EA802BDE845F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"599E1B58-DE28-5C0A-97A1-6797C070812D","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AD24C7D2-E412-587B-8606-BED2BC2F37B4'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"AD24C7D2-E412-587B-8606-BED2BC2F37B4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Smith Seated Shoulder Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that the handles are at shoulder level.","Sit on the machine with your back against the pad and your feet flat on the floor.","Grasp the handles with an overhand grip and lift them off the supports, extending your arms fully.","Lower the handles down to shoulder level, keeping your elbows slightly bent.","Press the handles up overhead until your arms are fully extended.","Pause for a moment at the top, then slowly lower the handles back down to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7D27CCEA-564D-5925-94D6-263F3A4C89D1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6AD278F4-3619-5E6F-845C-8DA91E152FF4","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E4733133-4F18-56BB-B7A0-44FC63816731","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"51AA56F6-E85B-5A2A-81A8-82899FB1B0E6","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B845326E-B32D-527E-BA36-EFB531FA6D5C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"B845326E-B32D-527E-BA36-EFB531FA6D5C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Smith Seated Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench in front of a Smith machine with your feet flat on the ground.","Grasp the barbell with an underhand grip, hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off.","Slowly curl your wrists upward, bringing the barbell towards your forearms.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"23FE9C42-96A2-523E-BA55-F24673270E90","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6AF4B9F7-92D5-5157-92E3-1128FA2C63A9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9799D6C1-629A-544F-9F3B-B2F0F76D780E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9204534E-A119-5DDF-80D9-F621EA75D0C0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6C49022E-C4DD-53E5-B5B2-49D651500E48'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"6C49022E-C4DD-53E5-B5B2-49D651500E48","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Smith Shoulder Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the smith machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lift the bar off the rack and position it at shoulder level, with your elbows bent and palms facing forward.","Press the bar upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the bar back down to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"5A9C07A4-C63F-55A8-8015-D5FBE9D52806","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"3FAF6163-E744-55FD-8ABA-D1EDEE6811E1","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"66F3C925-E4ED-57B9-AA38-894592A14C5F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"DFCC7768-9569-5A79-B824-7FC967A91983","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6562219C-B88E-5488-BB8E-3C4C277DB5CA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"6562219C-B88E-5488-BB8E-3C4C277DB5CA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Smith Shrug","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your arms straight and your shoulders relaxed.","Lift your shoulders up towards your ears, squeezing your traps at the top.","Hold for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"FCB1DB96-BCC8-5BD1-B5A1-525AC089DC50","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F0B3A801-4384-56A3-B3F7-9142069CBCF5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"2F6334E5-0AB7-57E8-9631-61BF20EF5E59","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"95F9E2EA-7A31-5952-A957-B7280975AD11","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FF9095E8-0237-5951-844C-74DC889E881D'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"FF9095E8-0237-5951-844C-74DC889E881D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings"],"name":"Smith Single Leg Split Squat","notes":"","plannedSets":3,"proTips":["Stand in front of the smith machine with your feet shoulder-width apart.","Place one foot behind you on a bench or step, with your toes pointing forward.","Hold onto the smith machine bar for stability.","Bend your front knee and lower your body down into a lunge position, keeping your back straight.","Pause for a moment at the bottom, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9CC70833-F965-550C-B097-22E72EF8C2F6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"BD8283D0-8158-5BE1-95DC-9DFD1BF558ED","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E16E9FA7-EF83-53BD-A7BF-0D6FAC26FAAD","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2833EA97-D8D6-55A2-8E98-4937E7F547B0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3DC5CFA6-8F38-59F6-9B3B-4535E016889E'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"3DC5CFA6-8F38-59F6-9B3B-4535E016889E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Sprint Lunge","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the barbell at hip height.","Stand facing away from the machine with your feet shoulder-width apart.","Step back with your right foot and place it on the barbell, resting the top of your foot on the bar.","Bend your left knee and lower your body into a lunge position, keeping your back straight.","Push through your left heel to return to the starting position.","Repeat on the other side, stepping back with your left foot.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"F891ABC7-9259-5C8B-B528-B614B68E6664","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"717E2E37-AC19-5180-96E7-E60DE6070627","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0D9D6466-4DA0-5406-880F-4FCF1AF6D107","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"44B8662A-9363-552C-9489-57DEA80E7182","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('63A7D162-DA70-5094-998E-72A39A045DDB'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"63A7D162-DA70-5094-998E-72A39A045DDB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Squat","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the barbell at an appropriate height for your squat.","Stand with your feet shoulder-width apart, toes slightly turned out.","Position yourself under the barbell, resting it on your upper traps and shoulders.","Grip the barbell with a wide grip, slightly wider than shoulder-width apart.","Engage your core and unrack the barbell, stepping back to clear the rack.","Keeping your chest up and back straight, initiate the squat by bending at the hips and knees.","Lower your body until your thighs are parallel to the ground or slightly below.","Pause for a moment at the bottom, then drive through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9C0F3DC2-61BA-58AC-B7F7-965A06178A41","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A7CCBB83-917F-583A-8309-584397CC3E4E","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B88C2ACB-E6ED-5E32-972C-0D11266D9AED","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"EDFBD2A4-E9A9-5604-85F6-E29F2E24761C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('196CA4E8-E72B-5C63-8019-1B49391C5D90'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"196CA4E8-E72B-5C63-8019-1B49391C5D90","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Triceps"],"name":"Smith Standing Back Wrist Curl","notes":"","plannedSets":3,"proTips":["Stand facing the smith machine with your feet shoulder-width apart.","Grasp the barbell with an overhand grip, hands shoulder-width apart.","Keep your back straight and your elbows close to your body.","Slowly curl your wrists upwards, bringing the barbell towards your body.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E0D8625C-0963-54F5-9216-62615F456ED5","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"39683A60-9941-5BAE-AAFF-8D2212882E46","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CD9FCA4F-767C-5A9F-9DAC-48456B83DE37","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"1DE75822-1047-5C64-A693-F0BF2AED9867","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('506C467A-0878-59F1-A5E3-22D7244F4DBF'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"506C467A-0878-59F1-A5E3-22D7244F4DBF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Smith Standing Behind Head Military Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height of the smith machine so that the bar is at shoulder level.","Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lift the bar off the rack and step back, maintaining a stable stance.","Position the bar behind your head, resting on your upper traps.","Keep your core engaged and your chest lifted throughout the exercise.","Press the bar overhead by extending your arms, fully straightening them.","Pause briefly at the top of the movement, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0AE1F676-0F21-566A-958B-5016ACD8806D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"694DC911-1582-5F7A-9E88-286E2DA903B2","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4A24655D-8507-51BF-A1FE-150015BC4AAA","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"32AC7354-1ECC-5BEA-971D-9E211357834C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('14CF1632-C3B8-5ABD-BA08-C70E692F2B69'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"14CF1632-C3B8-5ABD-BA08-C70E692F2B69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Smith Standing Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the smith machine bar to a height that allows you to stand with your feet flat on the ground and your shoulders under the bar.","Position yourself under the bar with your feet shoulder-width apart and your toes pointing forward.","Place your hands on the bar for stability.","Engage your calves and slowly raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"76D9730E-E4DE-5EC9-AF65-2E7B023F6681","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"3873AA23-52A9-51D7-89CF-8DF8495C8EE4","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0E521F1F-3DF4-54C9-A291-D12F7822F3D0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E07FCF5B-331B-5BAC-A837-D0189D404FEE","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('006E47BD-14B0-5141-BC7F-FCA4E90E36C0'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"006E47BD-14B0-5141-BC7F-FCA4E90E36C0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Smith Standing Military Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it down to shoulder level, with your palms facing forward.","Press the barbell upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the barbell back down to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2B7A2053-6ECF-562A-AB8D-C23EFEDA21B3","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9EB4734C-B5B0-50BE-90D8-A7E556CD6723","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5A02F00F-3072-5691-89C3-0E69BF3D06DA","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"AD8740BC-B46A-57EE-92C0-4144368AA1E4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CB1DFC9C-C772-57C7-A442-8F70A90E1FA4'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Smith Machine","hint":"","id":"CB1DFC9C-C772-57C7-A442-8F70A90E1FA4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Smith Sumo Squat","notes":"","plannedSets":3,"proTips":["Set up the smith machine with the barbell at hip height.","Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Position yourself under the barbell, resting it on your upper back and shoulders.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E8A2A513-8B69-54D3-81EC-4A52C831FE27","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"81FA17B1-1133-5806-8594-247786A1450D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"BA835B96-440C-5A9A-B02A-ABC3B89C590D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2861D883-A833-5E88-931B-F5DBDE3A168C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4DAE0C59-A799-5BF7-B3B9-7547D5B3D1F8'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"4DAE0C59-A799-5BF7-B3B9-7547D5B3D1F8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Shins"],"name":"Smith Toe Raise","notes":"","plannedSets":3,"proTips":["Adjust the smith machine bar to a height that allows you to comfortably stand with your feet flat on the ground.","Position yourself under the bar with your shoulders directly below it and your feet shoulder-width apart.","Place the balls of your feet on a raised platform or weight plates, with your heels hanging off the edge.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and keep your back straight throughout the exercise.","Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"B6ECD252-A111-5770-8ED9-70A98ACE9304","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2117065E-95BC-5001-B6D6-6BE9CEC5EDC5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A965102A-96BF-5A01-81E8-9F4B58E30AEE","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4704FE9C-B530-5577-887C-05F13899F4A6","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B630193-7A2A-562A-BB2C-BD605918F2D4'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"0B630193-7A2A-562A-BB2C-BD605918F2D4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Smith Upright Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing the smith machine.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the barbell up towards your chin, leading with your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E77ABA65-1886-5166-A7F6-532DF9017E95","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C00977D1-E739-56BF-BF3A-6752F9959885","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"34A5E1DA-BF93-5A80-9558-7ACCA70EF77A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"A8E397D4-A999-582B-9742-6EB469C3BEC9","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B24F0810-A3FA-5F64-91C1-DD29207F101B'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"B24F0810-A3FA-5F64-91C1-DD29207F101B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Wide Grip Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the bench to a comfortable position on the smith machine.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows out to the sides.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"5DC08569-DD96-5C18-A816-89960E925DDD","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"DA5DE15B-FD73-567C-BF23-FE9FDE1442D3","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5592508D-7EE6-515B-AE2D-C78BB7764CEF","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"71979A16-EDF1-55CF-813A-EFE44BF78827","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BF8D9733-4AE5-5D2B-B5F0-8CABB6B31FA9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Smith Machine","hint":"","id":"BF8D9733-4AE5-5D2B-B5F0-8CABB6B31FA9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Smith Wide Grip Decline Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the decline bench to the desired angle.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows pointed outwards.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"99B66E9E-0425-5C68-8C41-A64E4845E9A5","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9AFCB0A1-133E-55CF-B06D-D1F62D4537A9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B1D3A888-CAFE-5484-ACCF-39227D1C4877","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"FF758F40-1B49-58E2-9CB5-12D1A3D3AF44","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A06E52E3-30D9-580E-AE68-6E8F1252482C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"A06E52E3-30D9-580E-AE68-6E8F1252482C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes","Calves"],"name":"Snatch Pull","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower into a squat position, gripping the barbell with an overhand grip.","Keep your back straight and chest up as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As the barbell reaches hip level, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.","As the barbell reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position.","Catch the barbell overhead with your arms fully extended and your knees bent.","Stand up by extending your hips and knees, keeping the barbell overhead.","Lower the barbell back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AA892EE6-DE4B-5186-B765-413EEA50A1F0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"80EDE092-3209-5F33-9729-B529458B936A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0DCD9C03-9063-5C27-BA92-8B4415872802","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3B7CA45C-E988-547D-9D44-C27E7D09AF6B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('66AC6B3A-0FD7-5BC4-AD13-16D9D87B60F3'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"66AC6B3A-0FD7-5BC4-AD13-16D9D87B60F3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Spell Caster","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Bend your knees slightly and hinge forward at the waist, keeping your back straight.","Extend your arm with the dumbbell towards the opposite foot, rotating your torso as you do so.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1067FBE0-28CC-5D83-8B71-B219B5F8DD49","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('928630A3-3C05-5C7D-8564-13D415970DA3'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"928630A3-3C05-5C7D-8564-13D415970DA3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Sphinx","notes":"","plannedSets":3,"proTips":["Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders.","Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor.","Hold this position for a few seconds, making sure to keep your neck in a neutral position.","Slowly lower your chest back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F450B8F1-35EE-5ECB-AC2D-D20FD4369A52","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('454F55EB-1DC4-508E-A2B8-A00D55AF9B6D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"454F55EB-1DC4-508E-A2B8-A00D55AF9B6D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Core","Chest","Shoulders"],"name":"Spider Crawl Push Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Bring your right knee towards your right elbow, keeping it off the ground.","As you bring your right knee back, simultaneously lower your body towards the ground by bending your elbows.","Push back up to the starting position and repeat with your left knee towards your left elbow.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"36BC0558-8DA4-57AF-AB0D-5AB4F1AF29B1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B899F7AA-4972-525A-A7CA-59DEE7DB6929'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B899F7AA-4972-525A-A7CA-59DEE7DB6929","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Hamstrings","Glutes"],"name":"Spine Stretch","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Place your hands on the ground behind you, fingers pointing towards your body.","Engage your core and slowly lean back, keeping your back straight.","Continue leaning back until you feel a stretch in your spine.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"080C415A-A03F-5118-88CB-F3FE3799FC3A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('2DA7A5E5-E095-515E-8E12-1EDBC643062E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2DA7A5E5-E095-515E-8E12-1EDBC643062E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Spine Twist","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Bend your knees and place your feet flat on the ground, hip-width apart.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and slowly twist your torso to the right, bringing your right elbow towards your left knee.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side, bringing your left elbow towards your right knee.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C7350C12-5C09-5F18-A438-40FBA0FEADED","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8E234D3D-7373-5B6D-81E8-2E90BB6F0173'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"8E234D3D-7373-5B6D-81E8-2E90BB6F0173","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Split Squats","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Take a step forward with one foot and place it about two feet in front of the other foot.","Lower your body by bending your knees and hips, keeping your back straight.","Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"60523630-F407-56A6-BB7E-2743F9E7ED61","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D752DF9A-4765-5E13-BD2B-60449955D929'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"D752DF9A-4765-5E13-BD2B-60449955D929","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves","Core"],"name":"Squat Jerk","notes":"","plannedSets":3,"proTips":["Start with the barbell resting on your shoulders, with your feet shoulder-width apart.","Lower your body into a squat position, keeping your chest up and your knees tracking over your toes.","As you reach the bottom of the squat, explosively drive through your legs and push the barbell overhead.","As the barbell reaches its peak, quickly drop into a split position, with one foot forward and one foot back.","Catch the barbell overhead with your arms fully extended and your back knee slightly touching the ground.","Stand up from the split position, bringing your feet back together.","Lower the barbell back to your shoulders and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E6FF24EB-F0FF-531D-8742-2789A4549ABC","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"54479F88-6F16-5DE3-B81D-65B4942C8986","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E637CA18-5AB0-52BD-9780-0822DFEA38B3","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"246DBED8-99A0-5220-8EC4-F1CFCF50D634","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CD9C6213-FC10-5F71-8DA6-4B95FAA641D9'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bosu Ball","hint":"","id":"CD9C6213-FC10-5F71-8DA6-4B95FAA641D9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Squat On BOSU Ball","notes":"","plannedSets":3,"proTips":["Place the bosu ball on the ground with the flat side up.","Stand with your feet shoulder-width apart and position yourself on top of the bosu ball.","Lower your body down by bending your knees and hips, as if sitting back into a chair.","Keep your chest up and your weight on your heels.","Lower yourself until your thighs are parallel to the ground.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6C18B372-F239-5236-9118-1C7D9397452B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A87A4EA3-FD6F-568E-A9C1-1E31A4A08A83'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"A87A4EA3-FD6F-568E-A9C1-1E31A4A08A83","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Core"],"name":"Squat To Overhead Reach","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes slightly turned out.","Lower your body down into a squat position by bending your knees and pushing your hips back.","As you come up from the squat, extend your arms overhead, reaching towards the ceiling.","Return to the starting position by lowering your arms and bending your knees to squat down again.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D677CE29-C212-5684-A164-E225661C04A1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0E40B669-376C-5DA7-A4AB-84B849C76F07'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"0E40B669-376C-5DA7-A4AB-84B849C76F07","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Core"],"name":"Squat To Overhead Reach With Twist","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes slightly turned out.","Lower your body into a squat position by bending your knees and pushing your hips back.","As you come up from the squat, raise your arms overhead and twist your torso to one side.","Return to the starting position and repeat the squat, this time twisting your torso to the opposite side.","Continue alternating sides with each squat repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6528349D-EDE8-54D4-8AE4-ECD21AB2C084","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DF593876-910D-515A-AE6A-6D646DEB45A9'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"DF593876-910D-515A-AE6A-6D646DEB45A9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Stability Ball Crunch (Full Range Hands Behind Head)","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly curl your upper body forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly lower your upper body back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8407DDE7-B4EF-57CD-937B-E9749F859690","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DD82087A-3BC4-5BA0-B2DD-4A7480612A5A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DD82087A-3BC4-5BA0-B2DD-4A7480612A5A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Core"],"name":"Stalder Press","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and your arms extended overhead.","Bend your knees slightly and engage your core.","Lower your body down into a squat position while keeping your arms extended overhead.","As you squat down, press your arms down towards the ground, engaging your triceps.","Pause for a moment at the bottom of the squat, then push through your heels to stand back up while simultaneously raising your arms back overhead.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A213C0D7-FFA8-55EB-A5F5-D1AD9C8776D8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('62DFF5C3-D659-53BD-B5E7-E2032268C378'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"62DFF5C3-D659-53BD-B5E7-E2032268C378","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Biceps","Forearms"],"name":"Standing Archer","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you at shoulder height, parallel to the ground.","Rotate your torso to the right, keeping your arms extended and your back straight.","As you rotate, extend your right arm forward and your left arm back, mimicking the motion of drawing a bowstring.","Hold the position for a moment, then return to the starting position.","Repeat the motion, this time rotating your torso to the left and extending your left arm forward and your right arm back.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"351E59B2-3EE7-50EF-9A4B-AB9310DF9839","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E5654DCA-9B9E-55F2-8EB1-94C10EBB222E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"E5654DCA-9B9E-55F2-8EB1-94C10EBB222E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Standing Behind Neck Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the barbell behind your neck with an overhand grip.","Keep your back straight and core engaged.","Press the barbell overhead by extending your arms, fully extending your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A5233147-9D8A-504E-A59D-EB37C509AC6E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"3005B272-CE7B-5A92-9CFF-9A627199255D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"32246027-252B-5C2C-93DE-55D5AA0148E7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C4F3B19B-15CB-5FCA-8289-E014E3EF789C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('29269103-DE57-5A16-929C-99BE5EDFB673'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"29269103-DE57-5A16-929C-99BE5EDFB673","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Standing Calf Raise (On A Staircase)","notes":"","plannedSets":3,"proTips":["Stand on the edge of a step or a sturdy platform with your heels hanging off and your toes on the step.","Hold onto a railing or wall for balance if needed.","Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7F2059C0-5DF4-5F84-AC61-16ECE1FAF2F6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ABC1A6E9-3606-5525-9F95-ED08BABB00ED'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"ABC1A6E9-3606-5525-9F95-ED08BABB00ED","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Standing Calves","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing forward.","Raise your heels off the ground as high as possible, standing on your toes.","Hold the position for a moment, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"27FF33A7-221C-53AE-A06C-948D2DEF6B40","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('19A98947-6727-5305-83B3-835A2CC2A6BE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"19A98947-6727-5305-83B3-835A2CC2A6BE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Standing Calves Calf Stretch","notes":"","plannedSets":3,"proTips":["Stand facing a wall or sturdy object, about an arm''s length away.","Place your hands on the wall or object at shoulder height.","Step back with one foot, keeping your heel flat on the ground.","Bend your front knee slightly and lean forward, keeping your back leg straight.","You should feel a stretch in your calf muscle.","Hold the stretch for 20-30 seconds.","Repeat on the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"9D8EA0BB-91E9-50BB-AC82-40C849A56EFC","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('70B4FA9A-7020-53D0-AD17-CD261D54F7A0'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Rope","hint":"","id":"70B4FA9A-7020-53D0-AD17-CD261D54F7A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Calves"],"name":"Standing Hamstring And Calf Stretch With Strap","notes":"","plannedSets":3,"proTips":["Stand upright with your feet shoulder-width apart.","Hold the strap with both hands and place it around the ball of your foot.","Keep your leg straight and slowly lean forward from your hips, keeping your back straight.","Feel the stretch in your hamstring and calf muscles.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat with the other leg.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"0CB3A42D-A5FD-5D05-8376-DF3313368B66","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('28779D97-F398-5C29-92C9-1BD3A2D241B1'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"28779D97-F398-5C29-92C9-1BD3A2D241B1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Obliques"],"name":"Standing Lateral Stretch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out to the sides, parallel to the ground.","Slowly lean your upper body to one side, feeling a stretch in your side and lats.","Hold the stretch for 15-30 seconds.","Return to the starting position and repeat on the other side.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"52FA97BC-59A8-5B61-82B6-9309A2142B9F","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('1EA666CD-48AE-50BB-81CB-236CA1E4BBA9'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1EA666CD-48AE-50BB-81CB-236CA1E4BBA9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Abdominals"],"name":"Standing Pelvic Tilt","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Place your hands on your hips or let them hang by your sides.","Engage your core muscles and tilt your pelvis forward, pushing your lower back towards the wall behind you.","Hold the position for a few seconds, then release and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"72E6785D-A165-5D35-990D-A344F5904D5B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFA63E9C-06EC-5AB1-8FE7-2A0249E43996'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AFA63E9C-06EC-5AB1-8FE7-2A0249E43996","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes"],"name":"Standing Single Leg Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and your hands on your hips.","Shift your weight onto your left leg and lift your right foot off the ground, bending your knee.","Slowly curl your right heel towards your glutes, squeezing your hamstring.","Pause for a moment at the top, then slowly lower your right foot back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"657D164A-5262-52F2-BC55-6DF21EBC9256","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5ADEEBEB-CD77-54AD-8241-50FEE87993A8'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Roller","hint":"","id":"5ADEEBEB-CD77-54AD-8241-50FEE87993A8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Lower Back","Shoulders"],"name":"Standing Wheel Rollerout","notes":"","plannedSets":3,"proTips":["Start by standing tall with your feet shoulder-width apart and the wheel roller in front of you.","Bend at your waist and slowly roll the wheel forward, keeping your back straight and your core engaged.","Continue rolling forward until you feel a stretch in your abs and your body is extended as far as possible.","Pause for a moment, then slowly roll the wheel back towards your body, returning to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3C1207FB-93D6-5153-80CE-153804AE9A4D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B688CBCD-C094-5970-AB05-DEB72BADFACF'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B688CBCD-C094-5970-AB05-DEB72BADFACF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Star Jump","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms by your sides.","Bend your knees slightly and jump up explosively.","As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body.","Land softly on the balls of your feet with your knees slightly bent.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('8CEE3981-D6CD-5303-8566-140B4CB1E917'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Cardio Machine","hint":"","id":"8CEE3981-D6CD-5303-8566-140B4CB1E917","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Stationary Bike Run V. 3","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position to ensure proper alignment.","Place your feet on the pedals and secure them with the straps if available.","Start pedaling at a comfortable pace.","Maintain a steady rhythm and increase the resistance as desired.","Engage your core muscles to maintain stability and proper posture.","Continue pedaling for the desired duration of your workout.","Gradually decrease the resistance and slow down before coming to a complete stop.","Stretch your legs and cool down after the workout."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('B8D89A77-0B62-5DD9-8416-4ADEA379C8A5'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Machine","hint":"","id":"B8D89A77-0B62-5DD9-8416-4ADEA379C8A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Stationary Bike Walk","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position on the stationary bike to ensure proper alignment.","Place your feet on the pedals and secure them with the straps if available.","Start pedaling at a comfortable pace, keeping your back straight and core engaged.","Maintain a steady rhythm and increase the resistance level if desired.","Continue pedaling for the desired duration of your cardio workout.","Cool down by gradually reducing your pace and resistance level.","Stretch your leg muscles after the workout to prevent tightness and promote recovery."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('9239A8C8-508A-522E-BE76-910B4DB9B6F0'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9239A8C8-508A-522E-BE76-910B4DB9B6F0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest"],"name":"Straddle Maltese","notes":"","plannedSets":3,"proTips":["Start by hanging from a pair of rings with your arms fully extended and your body in a straight line.","Spread your legs wide apart, forming a straddle position.","Engage your core and slowly lower your body until your arms are parallel to the ground.","Hold this position for a few seconds, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2B5D7874-0B8F-5739-BC76-6C58D75FA4D4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4492AFFC-01D8-5FAA-846C-C7CF6C575B42'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"4492AFFC-01D8-5FAA-846C-C7CF6C575B42","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps","Chest"],"name":"Straddle Planche","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and your feet spread wide apart.","Engage your core and slowly shift your weight forward, bringing your shoulders over your hands.","Bend your elbows and lower your body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"52361D01-7C86-58B2-8894-662C4F55ABD8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('37414E0A-8683-508E-8270-9D2797A890B7'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"37414E0A-8683-508E-8270-9D2797A890B7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abductors","Glutes","Hamstrings"],"name":"Straight Leg Outer Hip Abductor","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs straight and stacked on top of each other.","Place your bottom arm under your head for support.","Engage your core and lift your top leg as high as possible without rotating your hips or leaning backward.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"161DD8BB-AF75-53AB-B820-DAD4E91F2F39","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8825C2CC-C979-574A-947B-BA03E707A849'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8825C2CC-C979-574A-947B-BA03E707A849","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Core","Shoulders"],"name":"Superman Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","As you lower your body, simultaneously lift your right arm and left leg off the ground, extending them straight out.","Pause for a moment at the top, then lower your arm and leg back down while pushing yourself back up to the starting position.","Repeat the movement, this time lifting your left arm and right leg.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BFE27E50-7278-55A5-B593-01E0FB6D73F8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8631BBC0-735A-5C21-808E-B6A01F917FA4'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8631BBC0-735A-5C21-808E-B6A01F917FA4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Suspended Abdominal Fallout","notes":"","plannedSets":3,"proTips":["Attach a suspension trainer to a high anchor point and adjust the straps to waist height.","Stand facing away from the anchor point and hold the handles with your arms extended in front of you.","Lean forward at the waist, keeping your body straight and your core engaged.","Lower your body as far as you can while maintaining control and tension in your abs.","Pause for a moment at the bottom, then slowly raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C7673A89-684F-5884-8C49-A4812ADC1396","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2D3D192B-95A0-57A1-87F1-2B64826AFA1A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2D3D192B-95A0-57A1-87F1-2B64826AFA1A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Suspended Push-Up","notes":"","plannedSets":3,"proTips":["Find a suspension trainer and adjust it to an appropriate height.","Stand facing away from the anchor point and hold the handles with an overhand grip.","Walk your feet forward, leaning your body forward until your weight is supported by the suspension trainer.","Keep your body straight from head to heels, engage your core, and lower your chest towards the handles.","Push through your chest and arms to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2C5E64EE-53C7-5F98-9B3F-D51413DAB60F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AE956CEA-EBEC-59AD-88B0-6DE7EC337BA5'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AE956CEA-EBEC-59AD-88B0-6DE7EC337BA5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Suspended Reverse Crunch","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees up towards your chest, curling your pelvis towards your ribcage.","Pause for a moment at the top, then slowly lower your knees back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1715543E-036B-5E71-A4CF-3996A3AA64ED","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5BDF32E2-87B2-58B0-BFD5-EF32FE64E5E1'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5BDF32E2-87B2-58B0-BFD5-EF32FE64E5E1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Suspended Row","notes":"","plannedSets":3,"proTips":["Set up a suspension trainer at an appropriate height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the handles with an overhand grip, palms facing each other.","Lean back, keeping your body straight and your heels on the ground.","Pull your chest towards the handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F91BA711-E630-585D-993F-105FD8331FB4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DB9A5B03-F713-5228-B4A7-68EA0F31801F'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"DB9A5B03-F713-5228-B4A7-68EA0F31801F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Suspended Split Squat","notes":"","plannedSets":3,"proTips":["Stand facing away from a suspension trainer with your feet shoulder-width apart.","Extend one leg forward and place the top of your foot in the foot cradle of the suspension trainer.","Bend your standing leg and lower your body down into a lunge position, keeping your chest up and your knee in line with your toes.","Push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B6533984-E6C0-5D17-88AA-A1E307976C01","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('313B36F2-09F6-58AC-875A-0CC984D51991'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"313B36F2-09F6-58AC-875A-0CC984D51991","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Calves"],"name":"Swimmer Kicks V. 2","notes":"","plannedSets":3,"proTips":["Lie face down on a mat with your arms extended overhead.","Engage your core and lift your chest and legs off the ground simultaneously.","Kick your legs up and down in a fluttering motion, as if you were swimming.","Continue kicking for the desired number of repetitions.","Lower your chest and legs back down to the starting position."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1CB2D91F-5D52-58D4-88B2-4C06F69067E6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7144495E-7611-5A8C-B68A-DF14628B0BE0'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7144495E-7611-5A8C-B68A-DF14628B0BE0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Shoulders","Core"],"name":"Swing 360","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold your arms straight out in front of you, parallel to the ground.","Engage your core and swing your arms in a circular motion, rotating your torso as you do so.","Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions.","Remember to breathe throughout the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('A9A34888-6E1F-50E1-A925-A1454172B6B8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A9A34888-6E1F-50E1-A925-A1454172B6B8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Three Bench Dip","notes":"","plannedSets":3,"proTips":["Sit on a bench with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body until your upper arms are parallel to the ground.","Push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ADE24C1D-84DB-50A1-8281-9270B0239240","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9D6D73DB-A373-5B0B-8A91-422B1467B531'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Other","hint":"","id":"9D6D73DB-A373-5B0B-8A91-422B1467B531","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Core"],"name":"Tire Flip","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing the tire.","Bend your knees and hinge at the hips, lowering into a squat position.","Reach down and grab the bottom edge of the tire with both hands, fingers facing towards you.","Engage your glutes and leg muscles, and explosively drive through your legs to lift the tire off the ground.","As the tire flips over, use your upper body strength to guide it and maintain control.","Once the tire is fully flipped, quickly step back and reset your stance.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E1956D11-0863-5519-B117-36E4986B4B8D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now())
